INSERT INTO `collaborators` (`id`, `name`, `short_description`, `long_description`, `email`, `phone_number`, `picture`, `created_at`, `updated_at`) VALUES
(3, 'Caraman George', '<p>Co-fondator, ghid spiritual, viziune și structură</p>', '<p>&nbsp;Am ales să fiu aici cu inima deschisă și cu darul meu de a aduce oamenii împreună în spații de creație, iubire și transformare. Prin atelierele de artă, momentele de reflecție și lucrul cu energia, susțin procesul de reconectare la esență și trezire a conștiinței.&nbsp;</p><p>Contribuția mea nu se limitează la un singur proiect. Aduc acest plus de valoare oriunde sunt chemat – în comunități, în familie, în munca cu energia, în lucrul cu oamenii. Cu blândețe, cu structură și cu iubire, ajut la susținerea spațiilor în care oamenii își pot aminti cine sunt cu adevărat.&nbsp;<br>&nbsp;</p><p><strong>Un gând care mă ghidează:</strong></p><p><i>Iubesc să iubesc și să fiu iubit.</i></p><p><strong>Motto personal:</strong></p><p><i>Cunoașterea determină destinul.</i></p>', 'asociatialotusretreat@gmail.com', '0753645442', 'collaborators/GyTAZEND5j7fFtHrwOtbbMd1JtzZsF6zBnjW0Ccy.jpg', '2025-05-13 16:54:01', '2025-05-26 07:29:56'),
(4, 'Cristina Cechi', '<p>Cristina este o prezență blândă și luminoasă, un suflet cu inima larg deschisă și o profunzime rar întâlnită. Am cunoscut-o în 2023, iar din acel moment a devenit o parte esențială din drumul nostru – nu doar în proiect, ci și în inimile noastre. Prin mâinile ei curge energia inimii – aceea care vindecă, înalță și aduce frumusețe în lume. Picturile sale, încărcate cu simboluri sacre, sunt mai mult decât artă – sunt portaluri energetice care ating sufletul și schimbă vibrația unui spațiu.&nbsp;</p><p>Fiecare tablou poartă o parte din esența ei: iubire, puritate, credință. Cristina creează și obiecte handmade încărcate energetic, fiecare lucrat cu intenție și delicatețe, ca o rugăciune tăcută în formă vizibilă. Ne susține din inimă, mereu prezentă, cu o bunătate care vindecă și o prezență care aduce liniște.&nbsp;</p><p>&nbsp;</p><p>„Arta adevărată este iubire manifestată în formă vizibilă.” – Deepak Chopra</p>', '<p>Cristina este o prezență blândă și luminoasă, un suflet cu inima larg deschisă și o profunzime rar întâlnită. Am cunoscut-o în 2023, iar din acel moment a devenit o parte esențială din drumul nostru – nu doar în proiect, ci și în inimile noastre. Prin mâinile ei curge energia inimii – aceea care vindecă, înalță și aduce frumusețe în lume. Picturile sale, încărcate cu simboluri sacre, sunt mai mult decât artă – sunt portaluri energetice care ating sufletul și schimbă vibrația unui spațiu.&nbsp;</p><p>Fiecare tablou poartă o parte din esența ei: iubire, puritate, credință. Cristina creează și obiecte handmade încărcate energetic, fiecare lucrat cu intenție și delicatețe, ca o rugăciune tăcută în formă vizibilă. Ne susține din inimă, mereu prezentă, cu o bunătate care vindecă și o prezență care aduce liniște.</p><p>&nbsp;</p><p>&nbsp;„Arta adevărată este iubire manifestată în formă vizibilă.” – Deepak Chopra</p>', NULL, NULL, 'collaborators/So90yZPe7nRHbp9Sk7xuIWoVfsS0H38qFghU6Khu.jpg', '2025-05-13 16:54:32', '2025-06-24 05:14:28'),
(5, 'Sandra Caraman', '<p>Co-fondator, Terapeut și Ghid în procese de transformare interioară</p>', '<p>&nbsp;</p><p>Cred că fiecare om are un loc al lui în lume – o amprentă unică, un dar sacru care așteaptă să fie reamintit, activat și oferit mai departe.</p><p>Darul meu este de a ghida și susține procesele de transformare interioară. Ofer un spațiu sigur și blând în care oamenii își pot recunoaște rănile, își pot reaminti cine sunt cu adevărat și pot accesa o vindecare profundă și autentică.<br>Acest dar îl duc cu mine peste tot – în sesiuni individuale sau de grup, în meditații, ateliere, retreaturi, în conversații intime și în prezența mea tăcută acolo unde este nevoie.</p><p>Lucrez intuitiv, folosind instrumente precum hipnoza terapeutică, respirația conștientă, meditația ghidată, ritualuri simbolice și explorarea energiilor feminine și masculine.</p><p>Motto personal:<br>“Suntem cu totii scântei divine, daruri pentru această lume. Fiecare pas pe care îl facem are sens, fiecare cuvânt pe care îl rostim contează.“</p>', 'asociatialotusretreat@gmail.com', '0760696009', 'collaborators/EXOMeva2H7rQlkFUycpBJ4IsEbxPdnZTYefWvPa8.jpg', '2025-05-13 19:36:44', '2025-05-24 18:10:34'),
(7, 'Mario Plesoiu', '<p>Artist</p>', '<p>Darul personal este muzica și meditația. Pe parcursul evenimentelor voi oferi muzica Live de Handpan și voce, workshopuri de meditații ghidate.<br>&nbsp;</p><p>Motto-ul meu este: &nbsp;“Omul devine ceea ce gândește în inima sa.”<br>&nbsp;</p>', NULL, '0739691166', 'collaborators/YU9T1frD9UufdmgWgi3I3TsSo48O68pEHT9OkQvA.jpg', '2025-05-24 18:15:34', '2025-05-26 14:58:00'),
(8, '⁠Larissa Koncz - Arhitect', '<p>Arhitect&nbsp;</p>', '<p>Darul meu personal este creativitatea și îl ofer prin idei, variante și toată munca de proiectare pe care o desfășor pentru ca acest centru să fie tot ce ne-am dorit.</p><p>Motto-ul personal: Eu sunt creatorul propriei mele realități.<br>&nbsp;</p>', 'Larikappa@gmail.com', '0724077926', 'collaborators/mlaBGEq1KVCaGP43ir2aqfvboeCuQDOOhMis6Rz0.jpg', '2025-05-26 18:18:09', '2025-05-26 18:18:09'),
(9, 'Cristina Cojocaru', '<p>Strategy manager&nbsp;</p>', '<p>Contribui la creșterea sustenabilă și viziunea pe termen lung a proiectului.</p><p>Motto-ul meu este: “Born free”&nbsp;</p><p><strong>Date de contact:</strong></p><p><strong>&nbsp;Instagram: freedomwithchristina</strong></p>', NULL, NULL, 'collaborators/hI1znJiuMfpisRFoiDBEW5aIPFHfXPcwDEhy508m.jpg', '2025-05-28 18:36:59', '2025-05-28 18:40:16'),
(10, 'Darius Hotima', '<p>Programare Mentala&nbsp;</p>', '<p>Darul meu este capacitatea de a înțelege profund atât mecanismele minții, cât și dimensiunea sufletului. Acest dar se concretizează prin facilitarea de sesiuni, ateliere și ghidaje care îmbină cunoașterea psihologică cu înțelepciunea spirituală. Ofer sprijin celor care vor să își curețe energia, să își activeze conștiința și să se întoarcă la esența divină din ei.</p><p>Motto-ul personal: Invata constant din orice situatie!</p><p>Mă găsiți pe instagram &nbsp;@htmdarius.ro</p>', NULL, '0747601089', 'collaborators/48Lu5XgaOGXi2m0cFzVTz3YRbtb5yhc9WQ1jI5Wi.jpg', '2025-06-07 06:15:52', '2025-06-07 12:52:51'),
(11, 'George Olteanu', '<p>Membru activ</p>', '<p>&nbsp;Gimnastică psihosomatică, breathwork, nutriție vie, terapie prin dans – pentru un trup viu și un suflet în mișcare. Ghid Turistic al centrului Calea Luminii.</p><p>Motto-ul personal: ‘Iubeste-ti aproapele ca pe tine insuti’ Iisus!&nbsp;</p>', NULL, '0741470049', 'collaborators/qMKtdclMAS5IY6jJXYQ1EEMjiKU8O1JwCtXI6Z1w.jpg', '2025-06-07 12:52:33', '2025-06-11 07:23:49'),
(12, 'Razvan Dinca', '<p>Fondator Awaken a New You, lider spiritual, speaker, antreprenor, un ghid al vieții si spiritualității.</p>', '<p>Sunt Fondatorul Awaken a New You, lider spiritual, speaker, antreprenor, un ghid al vieții si spiritualității. Fiind un student al creșterii personale și spirituale continue de la vârsta de aproximativ 20 de ani, pasiunea mea principală este să lucrez cu oameni, susținandu-i și ghidându-i în calatoria vieții pe toate aspectele ei, ceea ce fac de mai bine de 10 ani. Misiunea mea este să susțin cât mai multe suflete în procesul lor de Trezire și atingere a nivelului de Conștiință, a Iubirii și peste.<br>&nbsp;</p><p>Motto-ul personal: Iubirea nu este doar un sentiment, ci o stare de conștiință care transforma tot ce atinge.&nbsp;</p><p>Instagram: @dinca_razvan</p>', 'razvan.cosmin.dinca@gmail.com', NULL, 'collaborators/86d11vkiuPfiwt72qZt4hzhjCuFrMCYRJGSBZbJP.jpg', '2025-06-11 18:17:14', '2025-06-11 19:43:28'),
(13, 'Ramona Dima', '<p>Co-Fondator Awaken a New You</p>', '<p>Am avut întotdeauna o pasiune puternica pentru întelegerea functionarii Universului. În drumul meu, am explorat initial aceste aspecte dintr-o perspectiva stiintifica, focalizându-ma pe cunoasterea mentala si rationala. Cu timpul, însa, am descoperit că adevărurile profunde si semnificative vin dintr-o sursa total diferită - din interiorul fiecaruia dintre noi, din adâncurile Sufletului. Misiunea mea fiind sa ajut cât mai multe persoane să atingă echilibrul între rațional si suflet, pentru a se bucura de viață într-un mod autentic și aliniat cu Sufletele lor.</p><p>Motto-ul personal: ⁠Fiecare Suflet are propria Magie. Protejează-o!</p><p>⁠Instagram: &nbsp;@ramona__dima&nbsp;</p>', 'dima.ramonagabriela@yahoo.com', NULL, 'collaborators/9izid2gnJLMlo9MVZARDepg9eOJzB4lqXHrUc05g.jpg', '2025-06-11 18:30:58', '2025-06-11 18:30:58'),
(14, 'Larisa Cernescu', '<p>Arhitect si designer de interior<br>&nbsp;</p>', '<p>Transform spatiile în sanctuare care vindeca, inspiră și reflectă liniste și conectare. Prin design aduc liniste, echilibru si frumusete acolo unde oamenii vin sa se regaseasca.</p>', 'larisa@infinitivedesignstudio.ro', '0745187172', 'collaborators/RT1YsNwrxq5hu24v9g1jmwIT6lAKINasNi0CxVFM.jpg', '2025-06-24 04:57:44', '2025-06-24 04:57:44');
