INSERT INTO `contact_us` (`id`, `name`, `email`, `phone`, `message`, `created_at`, `updated_at`) VALUES
(3, 'Flaviu', 'forza_u@yahoo.com', '0745601607', 'Salutare \r\nSunt interesat de o Piramida de cupru cu inel tensor 177 MHz.\r\nMă interesează dimensiunile acesteia și anumite detalii legate de beneficii.\r\nVa mulțumesc', '2025-06-16 10:46:14', '2025-06-16 10:46:14');
INSERT INTO `events` (`id`, `name`, `description`, `disabled`, `starts_at`, `ends_at`, `price`, `created_at`, `updated_at`) VALUES
(2, 'Tabără conectării cu străbunii', '<p>Te invităm într-o călătorie profundă, transformatoare, in perioada 23-27 iulie 2025, la poalele munților Parâng, în satul Baia de Fier, la Pensiunea Eva– acolo unde pământul păstrează vii poveștile neamului și ecourile străbunilor.</p><p>Vom lucra pe arborele genealogic, nu doar cu sufletul, ci și cu mâinile: în cadrul atelierului de creație, fiecare participant va realiza un copac simbolic din cupru și cristale, cu ajutorul căruia se vor curăța rănile și ne vom conecta cu darurile și lumina străbunilor. La final, vei pleca acasă cu propria creație – un arbore unic, sacru si încărcat energetic.</p><p>⸻</p><p>Ce vei experimenta împreună cu noi in aceasta călătorie interioară:</p><p>•⁠ &nbsp;⁠⁠Curatari profunde ale ADN ului, ale liniei materne și ale liniei paterne;<br>•⁠ &nbsp;⁠⁠Meditații ghidate însoțite de sesiuni de respirație conștiente;&nbsp;<br>•⁠ &nbsp;⁠Rugăciuni ale inimii;<br>•⁠ &nbsp;⁠⁠Vibrații și sunete ancestrale la handpan și la boluri tibetane;<br>•⁠ &nbsp;⁠⁠Vom lucra în profunzime pentru a alchimiza, a ierta și a ne deschide către iubirea și moștenirea luminoasă a neamului nostru;<br>•⁠ &nbsp;⁠⁠Atelier creativ: Arborele neamului - creație simbolică din cupru și cristale;<br>•⁠ &nbsp;⁠⁠Foc de tabără sub cerul liber;<br>•⁠ &nbsp;⁠⁠Momente de conectare și împărtășire a experiențelor trăite, de eliberare, de binecuvântare și de cântare;<br>•⁠ &nbsp;⁠⁠Excursie la Peșteră Polovracilor și la Grota Haiducilor;<br>•⁠ &nbsp;⁠⁠Un moment special pe care îl vom trăii împreună: lansarea celei de a 12-a carte a lui Răzvan Eugen Cretan o lucrare profundă intitulată: ‘Sfântă spovedanie cu Dumnezeu’ &nbsp;<br>este o carte despre legătura profundă cu Dumnezeu , dincolo de frica, dogme și blocaje.</p><p>⸻</p><p>Schimbul energetic financiar include:<br>Cazare + Meniu lacto-vegetarian + Toate materiale necesare pentru atelierul de creație.</p><p>Pentru informații suplimentare legate de locație, cost, locuri disponibile, ne puteți contacta in privat:</p><blockquote><p>Whatsapp: 0753645442&nbsp;<br>Sau accesând linkul: <a href=\"https://wa.me/message/QMJPVUKL3LTKA1\">https://wa.me/message/QMJPVUKL3LTKA1</a></p></blockquote><p>Te așteptăm cu brațele deschise!</p><p>⸻</p><p>Ne poți cunoaște pe noi cei care îndrumăm aceasta experiența accesând link-urile de mai jos.</p><p>Mario Pleșoiu:</p><p>Ascultă-l pe Mario aici – <a href=\"https://youtube.com/playlist?list=PL5rEA1jFDOTduoTUGKD2AWyj35KjcCVMO&amp;si=3keURDgHdUSjBCNX\">https://youtube.com/playlist?list=PL5rEA1jFDOTduoTUGKD2AWyj35KjcCVMO&amp;si=3keURDgHdUSjBCNX</a></p><p>Răzvan:</p><p>[Citește un fragment sau ascultă-l pe Răzvan aici – &nbsp;<a href=\"https://youtu.be/7-8L4y50qO4?feature=shared\">https://youtu.be/7-8L4y50qO4?feature=shared</a></p><p><a href=\"https://youtube.com/@cercretaneugenrazvan?feature=shared\">https://youtube.com/@cercretaneugenrazvan?feature=shared</a></p><p>Sandra:</p><p>Accesează o meditație gratuită cu Sandra – <a href=\"https://youtu.be/L7Xr_GhERkc?si=BV-zXP2KaaMTKJ_f\">https://youtu.be/L7Xr_GhERkc?si=BV-zXP2KaaMTKJ_f</a></p><p><br>George: <a href=\"https://www.facebook.com/share/163JXwkgvS/?mibextid=wwXIfr\">https://www.facebook.com/share/163JXwkgvS/?mibextid=wwXIfr</a></p>', 0, '2025-07-23 00:00:00', '2025-07-27 00:00:00', 2500.00, '2025-05-13 10:38:44', '2025-05-17 07:16:17'),
(3, 'AWAKENING THE WARRIOR WITHIN', '<p>&nbsp; &nbsp; &nbsp;&nbsp;<strong>Fire &amp; Ice – Călătoria Transformării Interioare</strong></p><p><strong>Un retreat transformational prin FOC, GHEATA si CURAJ autentic!</strong></p><p><strong>Un retreat pentru cei care simt că a sosit momentul să-și întâlnească cu adevărat puterea interioară.</strong></p><p>Te-ai simțit vreodată prins într-un zid invizibil de frici, amânări sau limite?</p><p>Simți, undeva în adâncul tău, că potențialul tău este mult mai vast decât realitatea pe care o trăiești acum?</p><p>Ai auzit chemarea acelui Luptător interior care vrea să iasă la lumină?</p><p><strong>Dacă inima ta răspunde “da”, atunci acest retreat este pentru tine.</strong></p><p>&nbsp;</p><h3><strong>🔥❄️</strong></h3><h3><strong>Fire &amp; Ice este o călătorie transformațională de 6 zile – intensă, sinceră și profund eliberatoare.</strong></h3><p>&nbsp;</p><p>Este despre a merge dincolo de limitele impuse de frică și condiționare.</p><p>Despre a te privi cu adevărat, cu blândețe și curaj.</p><p>Despre a lăsa în urmă vechile povești și a păși în noua ta versiune – mai autentică, mai vie, mai liberă.</p><p>&nbsp;</p><h3><strong>Ce vei trăi în această experiență unică:</strong></h3><p>&nbsp;</p><p><strong>🔥 Mers pe cărbuni încinși</strong> – O întâlnire directă cu frica.</p><p>Fiecare pas este o declarație către viață: <i>„Aleg să merg mai departe, oricât de înfricoșător pare.”</i></p><p>&nbsp;</p><p><strong>❄️ Stat în gheață</strong> – O lecție brutal de sinceră despre prezență.</p><p>Corpul va vrea să fugă, mintea va opune rezistență, dar sufletul va zâmbi. Aici te regăsești, complet și autentic.</p><p>&nbsp;</p><p><strong>🪂 Salt cu parașuta de la 3000 m</strong> – Încredere absolută.</p><p>Un dans cu necunoscutul, un salt simbolic în brațele vieții. Acolo unde renunți la control și îmbrățișezi libertatea.</p><p>&nbsp;</p><p><strong>🏔 Urcare pe Vf. Moldoveanu</strong> – Depășirea limitelor personale.</p><p>Fiecare pas în sus devine o victorie asupra îndoielii, o reconectare cu puterea ta profundă.</p><p>&nbsp;</p><p><strong>🌬 Sesiuni intense de Breathwork</strong> – Curățare emoțională și acces la claritate.</p><p>Respirația devine poartă. Către eliberare, liniște, reconectare cu sufletul tău.</p><p>&nbsp;</p><p><strong>🌑 Vindecarea fricii de întuneric</strong> – Coboară cu încredere în propriul subconștient.</p><p>Unde altădată fugeai, acum vei aprinde lumină.</p><p>&nbsp;</p><p><strong>📝 Rescrierea identității</strong> – Dintr-un spațiu de adevăr, nu de dorință.</p><p>După ce ai ars, ai înghețat, ai sărit, ai urcat și ai respirat, vine momentul renașterii. Aici alegi, cu inimă deschisă, cine ești cu adevărat.</p><p>&nbsp;</p><h3><strong>Cine te ghidează în această călătorie:</strong></h3><p>&nbsp;</p><p><strong>Răzvan Dincă</strong> – ghid al transformării, trainer internațional, vorbitor inspirațional și suflet dedicat trezirii conștiinței.</p><p>Cu peste 10 ani de experiență în lucrul cu oamenii, Răzvan îmbină cunoașterea occidentală a dezvoltării personale cu profunzimea spiritualității orientale.</p><p>Misiunea sa este simplă și profundă:</p><p><strong>Să sprijine cât mai multe suflete în procesul lor de trezire și de trăire a Iubirii – nu ca emoție, ci ca Stare de Conștiință.</strong></p><p>&nbsp;</p><h3><strong>Cu iubire și recunoștință, alegem să fim parte din această călătorie alături de Răzvan și echipa sa.</strong></h3><p>Vom fi acolo cu toată inima, sprijinind fiecare participant în procesul său unic de eliberare și renaștere.</p><p>&nbsp;</p><h3><strong>Înscriere și detalii:</strong></h3><p>&nbsp;</p><p>Există mai multe pachete disponibile pentru participare, în funcție de nevoile și intențiile tale.</p><p>Dacă simți că acest retreat te cheamă, te poti inscrie accesand direct site-ul oficial al evenimentului:</p><p><a href=\"https://awakenanewyou.com/fire-and-ice\">https://awakenanewyou.com/fire-and-ice</a></p><p>&nbsp;</p><p><strong>Fire &amp; Ice nu este doar un retreat. Este o trezire. Un pas spre cine ai fost mereu menit(ă) să fii.</strong></p><p>✨ Cu iubire, curaj și adevăr…</p><p>Te așteptăm. ❤️</p><p>&nbsp;</p>', 0, '2025-06-17 00:00:00', '2025-06-22 00:00:00', 1577.00, '2025-06-05 15:06:42', '2025-06-05 15:06:42');
