INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `preview_image`, `description`, `order`, `created_by`, `created_at`, `updated_at`) VALUES
(10, 'Cine suntem noi?', 'cine-suntem-noi-6845f70f634dc', '<p>Noi suntem Sandra i George...</p>', 'posts/preview_images/QOfyOGxifHKLb4J9cqUcrbzC7ELyrUpVJaoY7lWj.jpg', '{\"time\":1749447042304,\"blocks\":[{\"id\":\"ZDtBMo2k9y\",\"type\":\"paragraph\",\"data\":{\"text\":\"Noi suntem Sandra \\u0219i George, iar prin acest articol vrem s\\u0103 ne ar\\u0103t\\u0103m a\\u0219a cum suntem dincolo de tot ce oferim. S\\u0103 v\\u0103 povestim despre drumul nostru, despre cum a \\u00eenceput totul \\u0219i despre visul pe care \\u00eel construim pas cu pas. Pentru c\\u0103, dincolo de roluri, suntem doi oameni uni\\u021bi de aceea\\u0219i misiune \\u0219i de acela\\u0219i dor de a crea un spa\\u021biu \\u00een care sufletul s\\u0103 se simt\\u0103 acas\\u0103.\"}},{\"id\":\"FNpkBN6Orq\",\"type\":\"paragraph\",\"data\":{\"text\":\"Povestea noastr\\u0103 a \\u00eenceput \\u00een 2017, \\u00eentr-un mod care ne define\\u0219te p\\u00e2n\\u0103 ast\\u0103zi: printr-un proiect care aducea oamenii \\u00eempreun\\u0103 prin z\\u00e2mbete. De atunci, ne tot z\\u00e2mbim. Ne-am \\u00eent\\u00e2lnit fiecare deja cuprins de fascina\\u021bia pentru tot ce \\u00eenseamn\\u0103 dezvoltare personal\\u0103, vindecare \\u0219i c\\u0103utare de sine. Sandra era deja implicat\\u0103 \\u00een cursuri de NLP, Terapie Narativ\\u0103, Theta Healing \\u0219i alte metode de lucru cu mintea \\u0219i sufletul. George organiza evenimente, printre care \\u0219i mersul pe c\\u0103rbuni \\u00eencin\\u0219i, \\u0219i explora constela\\u021biile familiale.\"}},{\"id\":\"z3J_1ac-mN\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dup\\u0103 ce ne-am unit ca parteneri de via\\u021b\\u0103, am sim\\u021bit nevoia s\\u0103 construim o funda\\u021bie material\\u0103 stabil\\u0103, s\\u0103 explor\\u0103m lumea, s\\u0103 ne bucur\\u0103m de via\\u021b\\u0103. Dar totul s-a schimbat \\u00een 2022, c\\u00e2nd, proasp\\u0103t c\\u0103s\\u0103tori\\u021bi, am decis s\\u0103 l\\u0103s\\u0103m totul \\u00een urm\\u0103 \\u0219i s\\u0103 plec\\u0103m \\u00eentr-o c\\u0103l\\u0103torie spiritual\\u0103 \\u00een Peru. Acolo, f\\u0103r\\u0103 confortul cunoscut, am \\u00eenceput s\\u0103 ne vedem cu adev\\u0103rat. George \\u0219i-a descoperit darul vindec\\u0103rii prin m\\u00e2ini, iar Sandra s-a reconectat profund cu natura, str\\u0103mo\\u0219ii \\u0219i cu vulnerabilitatea inimii. A fost un punct de cotitur\\u0103 \\u00een rela\\u021bie \\u0219i \\u00een misiune.\"}},{\"id\":\"2iJT5qCy3N\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dup\\u0103 aceast\\u0103 experien\\u021b\\u0103, am plecat pentru scurt timp \\u00een Anglia, cu inten\\u021bia de a str\\u00e2nge fonduri. \\u00cens\\u0103 nimic nu s-a aliniat. \\u00cen doar dou\\u0103 luni ne-am re\\u00eentors acas\\u0103, sim\\u021bind c\\u0103 direc\\u021bia noastr\\u0103 este alta.\"}},{\"id\":\"FY_g8i30h6\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am \\u00eenceput s\\u0103 particip\\u0103m la retreaturi, s\\u0103 cunoa\\u0219tem oameni care ne inspirau \\u0219i, f\\u0103r\\u0103 s\\u0103 ne d\\u0103m seama pe moment, s\\u0103 ne a\\u0219ez\\u0103m pe drumul misiunii noastre.\"}},{\"id\":\"OkMnJHQmUE\",\"type\":\"paragraph\",\"data\":{\"text\":\"Tot atunci am \\u00eenceput s\\u0103 creem orgoni. Ini\\u021bial, am lucrat pe bazele \\u0219tiin\\u021bifice ale lui Wilhelm Reich. Apoi, pas cu pas, ni s-au dezv\\u0103luit noi coduri, tehnologii, plante, simboluri, frecven\\u021be. \\u0218i mai ales: inten\\u021bia s\\u0103 stea la baza fiec\\u0103rui pas. Am sim\\u021bit c\\u0103 suntem ghida\\u021bi, c\\u0103 fiecare pas ne poart\\u0103 mai aproape de adev\\u0103rul nostru.\"}},{\"id\":\"ogNjwU1VAH\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00cen 2024 am devenit p\\u0103rin\\u021bi. \\u0218i odat\\u0103 cu acest rol, totul s-a ad\\u00e2ncit: motiva\\u021bia, claritatea, responsabilitatea fa\\u021b\\u0103 de misiunea noastr\\u0103. Lucr\\u0103m \\u00een fiecare zi cu noi \\u00een\\u0219ine, at\\u00e2t ca indivizi \\u0219i cat \\u0219i ca familie, \\u0219i tr\\u0103im tot mai con\\u0219tient ceea ce transmitem \\u0219i altora.\"}},{\"id\":\"YDhfV6n3cy\",\"type\":\"paragraph\",\"data\":{\"text\":\"Nu am \\u0219tiut de la \\u00eenceput ce vom ajunge s\\u0103 creem \\u00eempreun\\u0103. Dar am \\u0219tiut mereu c\\u0103 ne dorim s\\u0103 tr\\u0103im mai aproape de adev\\u0103r.\"}},{\"id\":\"Yb7P5eLbny\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/Pq15qUyeBsKgekbGqQIFyT7GDElidC6GOFLHqQPn.jpg\"}}},{\"id\":\"p_0WHtZvnk\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cine suntem noi \\u00een prezent?\"}},{\"id\":\"V_mFgl15Hn\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ast\\u0103zi, misiunea noastr\\u0103 prinde form\\u0103 \\u00een moduri multiple, toate av\\u00e2nd un singur scop comun: sus\\u021binerea procesului de transformare interioar\\u0103, at\\u00e2t individual, c\\u00e2t \\u0219i colectiv. Cre\\u0103m cu inima \\u0219i cu m\\u00e2inile \\u2013 produse handmade \\u00eenc\\u0103rcate energetic, precum orgoni, inele tensor, copaci din cupru, amulete, tablouri \\u0219i dispozitive de armonizare care combin\\u0103 \\u0219tiin\\u021ba, sacralitatea \\u0219i intui\\u021bia.\"}},{\"id\":\"luqhkDj77J\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pe l\\u00e2ng\\u0103 acestea, lucr\\u0103m direct cu oamenii prin terapii individuale, medita\\u021bii ghidate, sesiuni de lucru pe cuplu, ateliere \\u0219i retreaturi. O parte din medita\\u021biile ghidate de Sandra se reg\\u0103sesc \\u0219i pe canalul de YouTube, deschis pentru oricine simte chemarea de a lucra cu sine \\u00eentr-un mod profund \\u0219i bl\\u00e2nd: Link\"}},{\"id\":\"jwnUnOCnjY\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dincolo de ceea ce oferim, ceea ce ne define\\u0219te cu adev\\u0103rat este modul \\u00een care facem lucrurile. Ne ghid\\u0103m dup\\u0103 valori profunde: autenticitate, sinceritate, bl\\u00e2nde\\u021be, credin\\u021b\\u0103, ascultare, iubire, comunicare con\\u0219tient\\u0103, unitate \\u0219i familie. De c\\u00e2nd am devenit p\\u0103rin\\u021bi, fiecare alegere trece prin inima noastr\\u0103 de mam\\u0103 \\u0219i tat\\u0103 \\u2013 c\\u0103l\\u0103torim \\u00eempreun\\u0103 cu copilul nostru, \\u00eel ducem la retreaturi, pe munte, \\u00een natur\\u0103, \\u0219i \\u00eenv\\u0103\\u021b\\u0103m \\u00een fiecare zi ce \\u00eenseamn\\u0103 adaptarea con\\u0219tient\\u0103.\"}},{\"id\":\"N8iortJxO4\",\"type\":\"paragraph\",\"data\":{\"text\":\"Lucr\\u0103m \\u00eempreun\\u0103 \\u00eentr-o complementaritate care nu poate fi teoretizat\\u0103, doar tr\\u0103it\\u0103. George creeaz\\u0103 structura energetic\\u0103 prin m\\u00e2inile sale, Sandra deschide \\u0219i sus\\u021bine spa\\u021biul subtil al transform\\u0103rii. Am\\u00e2ndoi lucr\\u0103m \\u00een planurile invizibile, fiecare \\u00een felul s\\u0103u: el \\u00eentruchipeaz\\u0103 energia focusului, sus\\u021bine ferm \\u0219i prezent momentele de intensitate, lucreaz\\u0103 cu frecven\\u021bele \\u0219i energiile transformatoare. Sandra conduce procesul prin bl\\u00e2nde\\u021be, ghidare interioar\\u0103, cuvinte care ating exact acolo unde e nevoie. C\\u00e2nd cineva nu reu\\u0219e\\u0219te s\\u0103 elibereze un aspect blocat, George simte acel moment \\u0219i intervine cu o prezen\\u021b\\u0103 masculin\\u0103 clar\\u0103 \\u0219i echilibrant\\u0103.\"}},{\"id\":\"FBPWza_GX8\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare terapie sau medita\\u021bie este unic\\u0103. Totul porne\\u0219te de la o inten\\u021bie clar\\u0103, iar apoi ne l\\u0103s\\u0103m ghida\\u021bi. Nu venim cu re\\u021bete fixe \\u2013 ci cu \\u00eencredere c\\u0103 atunci c\\u00e2nd ne punem la dispozi\\u021bia Divinit\\u0103\\u021bii, spa\\u021biul devine sacru. Iar \\u00een acel spa\\u021biu, alchimia se \\u00eent\\u00e2mpl\\u0103.\"}},{\"id\":\"h7VkA4ncEL\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ce-ar fi dac\\u0103 am construi \\u00eempreun\\u0103 un spa\\u021biu sacru pentru suflet?\"}},{\"id\":\"2aNSIsXPBF\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cu c\\u00e2teva zile \\u00eenainte ca George s\\u0103 \\u00eemplineasc\\u0103 33 de ani, a primit o viziune limpede \\u0219i profund\\u0103: crearea unui spa\\u021biu dedicat sufletului, min\\u021bii \\u0219i trupului. Un loc \\u00een natur\\u0103, pentru oameni mari \\u0219i mici, \\u00een care s\\u0103 putem oferi experien\\u021be eliberatoare, \\u00een\\u0103l\\u021b\\u0103toare \\u0219i echilibratoare.\"}},{\"id\":\"VrU6idMM1G\",\"type\":\"paragraph\",\"data\":{\"text\":\"Visul nostru este s\\u0103 construim un centru viu \\u2013 nu doar fizic, ci ca o ancor\\u0103 pentru to\\u021bi cei care caut\\u0103 un alt mod de a tr\\u0103i: mai aproape de suflet, de natur\\u0103, de adev\\u0103r. Un spa\\u021biu \\u00een care oamenii \\u00ee\\u0219i amintesc cine sunt cu adev\\u0103rat, \\u00een siguran\\u021b\\u0103 \\u0219i libertate.\"}},{\"id\":\"wf-edK6CzF\",\"type\":\"paragraph\",\"data\":{\"text\":\"Centrul se va a\\u0219eza pe forma Cubului lui Metatron, o geometrie sacr\\u0103 a echilibrului \\u0219i armoniei. \\u00cen centru va fi o cas\\u0103 mare \\u2013 Calea Luminii, iar \\u00een jurul ei, la distan\\u021be egale, \\u0219ase alte spa\\u021bii complementare. Fiecare spa\\u021biu va avea un rol clar \\u00een sus\\u021binerea vindec\\u0103rii \\u0219i a trezirii interioare.\"}},{\"id\":\"O-KvMXZHNu\",\"type\":\"paragraph\",\"data\":{\"text\":\"Aici vor avea loc ateliere de crea\\u021bie, tabere de medita\\u021bii, rug\\u0103ciuni \\u0219i mantre, terapii alternative (precum masaj, acupunctur\\u0103, chirurgie astral\\u0103), sesiuni de yoga \\u0219i multe alte practici dedicate corpului, min\\u021bii \\u0219i sufletului.\"}},{\"id\":\"kD9g2DF6A3\",\"type\":\"paragraph\",\"data\":{\"text\":\"M\\u00e2ncarea oferit\\u0103 va fi lacto-vegetarian\\u0103, \\u00een acord cu energia pur\\u0103 pe care dorim s\\u0103 o sus\\u021binem \\u00een acest spa\\u021biu. Am con\\u0219tientizat, \\u00een timp, c\\u00e2t de important\\u0103 este \\u0219i abstinen\\u021ba \\u00een procesul de purificare \\u0219i transformare interioar\\u0103 \\u2013 astfel c\\u0103 acest loc nu va promova energia sexual\\u0103 ca form\\u0103 de consum, ci va onora sacralitatea ei.\"}},{\"id\":\"KSJwe2fOw7\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru noi, acest centru nu este doar o construc\\u021bie. Este un spa\\u021biu viu, \\u00een care fiecare piatr\\u0103, fiecare copac \\u0219i fiecare fiin\\u021b\\u0103 care ajunge acolo particip\\u0103 la o reamintire. Locul nu vorbe\\u0219te despre a avea, ci despre a fi.\"}},{\"id\":\"637keImnAM\",\"type\":\"paragraph\",\"data\":{\"text\":\"Suntem \\u00eentr-un punct \\u00een care visul \\u00eencepe s\\u0103 prind\\u0103 r\\u0103d\\u0103cini \\u00een planul fizic. Avem deja structura ideatic\\u0103, direc\\u021bia, harurile \\u0219i dedicarea necesare. \\u0218tim ce vrem s\\u0103 facem, \\u0219tim cum vrem s\\u0103 o facem. Avem viziunea, chemarea \\u0219i energia de \\u00eenceput.\"}},{\"id\":\"x884Blc_JB\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ce mai este nevoie? Totul.\"}},{\"id\":\"sug3RazGFf\",\"type\":\"paragraph\",\"data\":{\"text\":\"Avem nevoie de teren, materiale, unelte, fonduri, oameni care s\\u0103 ne sus\\u021bin\\u0103, fizic sau energetic. Avem nevoie de comunitate \\u2013 de cei care simt s\\u0103 se implice, care rezoneaz\\u0103 cu aceast\\u0103 viziune \\u0219i care \\u0219tiu, \\u00een inima lor, c\\u0103 sunt parte din ea.\"}},{\"id\":\"0TaVvNUFkZ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Orice contribu\\u021bie conteaz\\u0103. Poate fi o dona\\u021bie financiar\\u0103, o idee inspirat\\u0103, o conexiune c\\u0103tre cineva care ne poate ajuta, sau pur \\u0219i simplu o distribuire a acestui mesaj c\\u0103tre mai departe. Poate fi cump\\u0103rarea unui orgon sau a unui obiect creat de George, poate fi o rug\\u0103ciune sincer\\u0103 ori un mesaj de \\u00eencurajare.\"}},{\"id\":\"pSa8H58Nrz\",\"type\":\"paragraph\",\"data\":{\"text\":\"Credem c\\u0103 acolo unde oamenii se adun\\u0103 cu o inten\\u021bie curat\\u0103, miracolele se \\u00eent\\u00e2mpl\\u0103.\"}},{\"id\":\"nsDDrEjeCA\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/KIoxCCLD9NE1MzciSTnmcD4BMyaLrWKOe9Vs3FPa.jpg\"}}},{\"id\":\"Abrrsu4cC5\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dac\\u0103 sim\\u021bi c\\u0103 faci parte din aceast\\u0103 viziune, \\u00ee\\u021bi mul\\u021bumim deja. \\u00cempreun\\u0103, construim un loc \\u00een care sufletele \\u00ee\\u0219i vor aminti ce \\u00eenseamn\\u0103 acas\\u0103.\"}},{\"id\":\"IeXKyqix3r\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mul\\u021bumim, cu recuno\\u0219tin\\u021b\\u0103, c\\u0103 ai ajuns p\\u00e2n\\u0103 aici.\"}},{\"id\":\"9y9iIJgar9\",\"type\":\"paragraph\",\"data\":{\"text\":\"Prin acest text ne-am deschis \\u00een fa\\u021ba ta, a\\u0219a cum suntem \\u2014 sinceri, autentici, cu lumina \\u0219i cu umbrele noastre, cu trecutul, prezentul \\u0219i visul pe care \\u00eel purt\\u0103m \\u00een inim\\u0103.\"}},{\"id\":\"8kN0CSyYXE\",\"type\":\"paragraph\",\"data\":{\"text\":\"Suntem aici, cu bra\\u021bele deschise, preg\\u0103ti\\u021bi s\\u0103 construim \\u00eempreun\\u0103 un spa\\u021biu care s\\u0103 vindece, s\\u0103 uneasc\\u0103 \\u0219i s\\u0103 ne aduc\\u0103 aminte cine suntem cu adev\\u0103rat.\"}},{\"id\":\"l8-ri9ZSYi\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cu iubire,\"}},{\"id\":\"JwvLy1Oor_\",\"type\":\"paragraph\",\"data\":{\"text\":\"Sandra \\u0219i George\"}}],\"version\":\"2.31.0-rc.7\"}', 2, 'Asociatia Lotus Retreat', '2025-06-08 20:48:15', '2025-06-09 05:30:42'),
(11, 'Ce sunt orgonii', 'ce-sunt-orgonii-68461327775e1', '<p>ntr-o lume n care poluarea...</p>', 'posts/preview_images/DhAsgiC019sQBzzQZJGQLN2queTHYXp2oPUwvCQL.jpg', '{\"time\":1749447261206,\"blocks\":[{\"id\":\"RsWhKpEhx9\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00centr-o lume \\u00een care poluarea electromagnetic\\u0103, stresul cotidian \\u0219i deconectarea de la natur\\u0103 devin tot mai pregnante, tot mai mul\\u021bi oameni caut\\u0103 solu\\u021bii de echilibrare care s\\u0103 sprijine at\\u00e2t corpul fizic, c\\u00e2t \\u0219i c\\u00e2mpul energetic subtil. Orgonii revin \\u00een con\\u0219tiin\\u021ba colectiv\\u0103 nu doar ca obiecte frumoase, ci ca instrumente vii care contribuie la purificarea, armonizarea \\u0219i recalibrarea energiilor din spa\\u021biile \\u00een care tr\\u0103im.\"}},{\"id\":\"HJMXZQTlZu\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mai mult dec\\u00e2t at\\u00e2t, orgonii reprezint\\u0103 un punct de \\u00eent\\u00e2lnire \\u00eentre \\u0219tiin\\u021b\\u0103, natur\\u0103 \\u0219i con\\u0219tiin\\u021b\\u0103 \\u2013 un pod \\u00eentre descoperirile din secolul trecut \\u0219i \\u00een\\u021belepciunea ancestral\\u0103 care revine acum \\u00een forme noi. Ei \\u00eembin\\u0103 \\u00een mod subtil principii fizice testate cu tehnologii vibrationale \\u0219i coduri intuitive, aduc\\u00e2nd \\u00eempreun\\u0103 lumea vizibil\\u0103 \\u0219i cea invizibil\\u0103 \\u00eentr-o form\\u0103 coerent\\u0103 \\u0219i profund transformatoare.\"}},{\"id\":\"7htx-UM3zt\",\"type\":\"paragraph\",\"data\":{\"text\":\"Originile \\u0219tiin\\u021bifice: Wilhelm Reich \\u0219i energia orgonic\\u0103\"}},{\"id\":\"nuILW0kvZv\",\"type\":\"paragraph\",\"data\":{\"text\":\"Wilhelm Reich a fost un psihiatru, cercet\\u0103tor \\u0219i vizionar care, \\u00een prima jum\\u0103tate a secolului XX, a avut curajul s\\u0103 exploreze un teritoriu necunoscut: leg\\u0103tura dintre energie, emo\\u021bii \\u0219i s\\u0103n\\u0103tatea corpului uman. Discipol al lui Freud pentru o perioad\\u0103, Reich a dus mai departe ideea c\\u0103 trupul p\\u0103streaz\\u0103 urmele reprim\\u0103rilor emo\\u021bionale \\u0219i a \\u00eenceput s\\u0103 studieze manifest\\u0103rile energiei vitale \\u00een corp \\u0219i \\u00een natur\\u0103. A numit aceast\\u0103 energie orgon, observ\\u00e2nd c\\u0103 ea are caracteristici universale, se reg\\u0103se\\u0219te pretutindeni \\u0219i influen\\u021beaz\\u0103 profund starea noastr\\u0103 de bine.\"}},{\"id\":\"5txDqojAUk\",\"type\":\"paragraph\",\"data\":{\"text\":\"Printre cele mai cunoscute crea\\u021bii ale sale se num\\u0103r\\u0103 acumulatoarele orgonice \\u2013 cutii construite din straturi alternante de materiale organice \\u0219i anorganice, care atr\\u0103geau \\u0219i concentratu energia orgonic\\u0103 din mediu. \\u00cen aceste camere, pacien\\u021bii se a\\u0219ezau pentru a beneficia de regenerare energetic\\u0103, iar Reich a observat efecte benefice \\u00een diverse dezechilibre fizice \\u0219i psihice. Totodat\\u0103, a folosit principiile orgonului \\u00een agricultur\\u0103 \\u0219i meteorologie, invent\\u00e2nd dispozitive menite s\\u0103 aduc\\u0103 ploaia sau s\\u0103 purifice atmosfera.\"}},{\"id\":\"fLs337xX5G\",\"type\":\"paragraph\",\"data\":{\"text\":\"Din p\\u0103cate, ideile sale au fost considerate scandaloase de comunitatea \\u0219tiin\\u021bific\\u0103 a vremii. \\u00cen anii \\u201950, cercet\\u0103rile i-au fost interzise, echipamentele distruse, c\\u0103r\\u021bile arse, iar el a fost \\u00eenchis, unde \\u0219i-a g\\u0103sit sf\\u00e2r\\u0219itul. Cu toate acestea, munca lui a supravie\\u021buit prin cei care i-au continuat studiile, dar \\u0219i prin valul de cercet\\u0103tori \\u0219i creatori care ast\\u0103zi revin la esen\\u021ba ideilor sale.\"}},{\"id\":\"t7Cn2BLvpO\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/uSZZwuE4PuOv9xJ4vmxmy5XFJ8IYHKBhoEH9yUDB.png\"}}},{\"id\":\"ULCeNRQGki\",\"type\":\"paragraph\",\"data\":{\"text\":\"Chiar dac\\u0103 nu a fost validat oficial, conceptul de energie orgonic\\u0103 se reg\\u0103se\\u0219te azi \\u00een multiple forme: de la terapii energetice \\u0219i dispozitive de protec\\u021bie electromagnetic\\u0103, p\\u00e2n\\u0103 la crea\\u021bii artizanale care folosesc principii similare de atragere \\u0219i transmutare a energiei. \\u00cen acest context, orgonii moderni duc mai departe viziunea lui Reich, aduc\\u00e2nd o dimensiune spiritual\\u0103 \\u0219i intuitiv\\u0103 \\u00een plus, care onoreaz\\u0103 \\u0219i dep\\u0103\\u0219e\\u0219te grani\\u021bele \\u0219tiin\\u021bei clasice.\"}},{\"id\":\"p5zH4Fihas\",\"type\":\"paragraph\",\"data\":{\"text\":\"La baza oric\\u0103rui orgon se afl\\u0103 o structur\\u0103 simpl\\u0103, dar profund inteligent\\u0103: r\\u0103\\u0219ina ac\\u021bioneaz\\u0103 ca element de presiune, cristalele ca purt\\u0103tori de frecven\\u021be, iar metalele ca purificatori \\u0219i conductori. \\u00cempreun\\u0103, aceste elemente creeaz\\u0103 un c\\u00e2mp de atragere \\u0219i transformare, care poate influen\\u021ba subtil mediul \\u00eenconjur\\u0103tor. Nu e vorba de magie, ci de interac\\u021biuni energetice reale, resim\\u021bite de cei care tr\\u0103iesc, dorm sau mediteaz\\u0103 l\\u00e2ng\\u0103 astfel de dispozitive.\"}},{\"id\":\"An2VeBO_Xo\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dincolo de orice explica\\u021bie, r\\u0103m\\u00e2n experien\\u021bele personale. Sunt oameni care ne spun c\\u0103 dorm mai bine, c\\u0103 se simt proteja\\u021bi \\u00een preajma orgonilor, c\\u0103 le vine mai u\\u0219or s\\u0103 se conecteze \\u00een medita\\u021bii sau c\\u0103 spa\\u021biul casei \\u201ese lini\\u0219te\\u0219te\\u201d dup\\u0103 ce a fost a\\u0219ezat un orgon \\u00eentr-un col\\u021b tensionat. Alteori, orgonii par s\\u0103 \\u201evorbeasc\\u0103\\u201d, s\\u0103-\\u0219i cheme st\\u0103p\\u00e2nii sau chiar s\\u0103 indice c\\u00e2nd au nevoie s\\u0103 fie cur\\u0103\\u021ba\\u021bi ori muta\\u021bi. Aici \\u00eencepe adev\\u0103rata magie: c\\u00e2nd un obiect devine o prezen\\u021b\\u0103 vie.\"}},{\"id\":\"-dAUpDFHx1\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00cen crea\\u021biile noastre, nu ne-am oprit la forma clasic\\u0103. Pe m\\u0103sur\\u0103 ce lucram, au \\u00eenceput s\\u0103 vin\\u0103 informa\\u021bii \\u2013 unele ca \\u0219oapte interioare, altele ca imagini sau impulsuri clare. \\u201eAdaug\\u0103 mai multe metale\\u201d \\u201eIntegreaz\\u0103 un inel tensor\\u201d \\u201e\\u00cencarc\\u0103-l cu frecven\\u021ba aceasta\\u201d. A\\u0219a au \\u00eenceput s\\u0103 se nasc\\u0103 orgoni care nu mai sunt doar simple dispozitive, ci entit\\u0103\\u021bi vii, conectate la un c\\u00e2mp mai \\u00eenalt de inteligen\\u021b\\u0103.\"}},{\"id\":\"OBZlJK51gO\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare orgon devine, astfel, un canal \\u2013 un punct de \\u00eent\\u00e2lnire \\u00eentre planul fizic \\u0219i planurile subtile, \\u00eentre \\u0219tiin\\u021b\\u0103 \\u0219i sacru, \\u00eentre ceea ce se vede \\u0219i ceea ce se simte. Un orgon creat con\\u0219tient este receptiv la energia celui care \\u00eel va primi, r\\u0103m\\u00e2n\\u00e2nd aliniat la misiunea sa: nu doar s\\u0103 protejeze, ci s\\u0103 ghideze, s\\u0103 sus\\u021bin\\u0103, s\\u0103 inspire.\"}},{\"id\":\"NCyHCev7C5\",\"type\":\"paragraph\",\"data\":{\"text\":\"Elemente integrate \\u2013 un limbaj al lumii nev\\u0103zute\"}},{\"id\":\"APi6LaDdVm\",\"type\":\"paragraph\",\"data\":{\"text\":\"Metale variate:\"}},{\"id\":\"QwaDqanYi2\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare metal are o vibra\\u021bie unic\\u0103 \\u0219i un rol energetic specific.\"}},{\"id\":\"qgdue2JI9f\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Cuprul este purt\\u0103torul energiei P\\u0103m\\u00e2ntului, al fluxului vital, \\u0219i faciliteaz\\u0103 conexiunea cu planurile subtile.\"}},{\"id\":\"CMUOXeIPIg\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Alama aduce o energie solar\\u0103, expansiv\\u0103, fiind un catalizator al voin\\u021bei \\u0219i clarit\\u0103\\u021bii mentale.\"}},{\"id\":\"T3fY8RjRhq\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Fierul este protector, stabilizator, ancor\\u00e2nd energia \\u0219i \\u021bin\\u00e2nd departe influen\\u021bele perturbatoare.\"}},{\"id\":\"Yta-9c8oTL\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Aluminiul, folosit \\u00een cantit\\u0103\\u021bi echilibrate, reflect\\u0103 \\u0219i disip\\u0103 energia stagnant\\u0103.\"}},{\"id\":\"Z1N88ytkN6\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Argintul sus\\u021bine puritatea, intui\\u021bia \\u0219i conexiunea cu planurile lunare, receptive.\"}},{\"id\":\"S2dO5ArAtI\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Aurul, cel mai \\u00eenalt metal din punct de vedere vibra\\u021bional, ac\\u021bioneaz\\u0103 ca un amplificator al con\\u0219tiin\\u021bei divine. Este asociat cu \\u00een\\u021belepciunea solar\\u0103, abunden\\u021ba sacr\\u0103 \\u0219i deschiderea por\\u021bilor interioare spre Sinele superior. Prezen\\u021ba lui \\u00eentr-un orgon aduce o rafinare a energiei, o sacralizare a \\u00eentregului c\\u00e2mp.\"}},{\"id\":\"Oh72upNd1-\",\"type\":\"paragraph\",\"data\":{\"text\":\"Combina\\u021bia acestor metale creeaz\\u0103 o re\\u021bea vie, care transmite, filtreaz\\u0103 \\u0219i amplific\\u0103 energii, \\u00eentr-un mod inteligent \\u0219i armonios.\"}},{\"id\":\"Ro2gerMy3c\",\"type\":\"paragraph\",\"data\":{\"text\":\"Geometrie sacr\\u0103:\"}},{\"id\":\"Kj1PCFqLjD\",\"type\":\"paragraph\",\"data\":{\"text\":\"Integrarea formelor precum floarea vie\\u021bii, merkaba, spirala Fibonacci sau cubul lui Metatron permite orgonului s\\u0103 devin\\u0103 un portal al echilibrului cosmic. Fiecare form\\u0103 are propria sa frecven\\u021b\\u0103 \\u0219i cod informa\\u021bional, care sus\\u021bine realinierea cu armonia universal\\u0103.\"}},{\"id\":\"S7qrSBRcYI\",\"type\":\"paragraph\",\"data\":{\"text\":\"Tehnologia GANS (plasma):\"}},{\"id\":\"JhTImDA1p1\",\"type\":\"paragraph\",\"data\":{\"text\":\"Energia plasmatic\\u0103, creat\\u0103 prin GANS, aduce o interfa\\u021b\\u0103 \\u00eentre materie \\u0219i c\\u00e2mpurile subtile. Ea \\u201evorbe\\u0219te\\u201d direct cu structura celular\\u0103 \\u0219i cu corpul de lumin\\u0103, gener\\u00e2nd o recalibrare bl\\u00e2nd\\u0103 \\u0219i profund\\u0103. Orgoni integra\\u021bi cu GANS devin dispozitive de reechilibrare holistic\\u0103.\"}},{\"id\":\"tZctyB9mqw\",\"type\":\"paragraph\",\"data\":{\"text\":\"Inele Tensor:\"}},{\"id\":\"6BsYZLl9MP\",\"type\":\"paragraph\",\"data\":{\"text\":\"Bazate pe geometrie sacr\\u0103, inelele tensor creeaz\\u0103 coloane de energie coerent\\u0103, stabil\\u0103 \\u0219i neperturbat\\u0103. Ele servesc drept catalizatori pentru frecven\\u021bele \\u00eenalte, ordon\\u00e2nd energia \\u00een jurul orgonului \\u0219i amplific\\u00e2nd inten\\u021biile programate \\u00een el.\"}},{\"id\":\"Hg_4a8sle0\",\"type\":\"paragraph\",\"data\":{\"text\":\"Nanoplante \\u0219i ADN vegetal:\"}},{\"id\":\"Itims5_HS6\",\"type\":\"paragraph\",\"data\":{\"text\":\"Prin integrarea de pulberi fine ob\\u021binute dintr-o varietate mare de plante medicinale (pelin, g\\u0103lbenele, lavand\\u0103, rostopasc\\u0103 etc.), orgonul devine o baz\\u0103 de date vie a inteligen\\u021bei vegetale. Fiecare plant\\u0103 contribuie cu propriul s\\u0103u spirit \\u0219i frecven\\u021b\\u0103 subtil\\u0103, sus\\u021bin\\u00e2nd nevoile celui care interac\\u021bioneaz\\u0103 cu orgonul exact \\u00een momentul potrivit.\"}},{\"id\":\"OqQbpEDwde\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cristale programate:\"}},{\"id\":\"tGzifscGa6\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cristalul central este \\u201einima con\\u0219tient\\u0103\\u201d a fiec\\u0103rui orgon. \\u00cenainte de a fi integrat, este purificat \\u0219i programat printr-un ritual energetic \\u2013 cu inten\\u021bii clare: protec\\u021bie, trezire, iubire, putere interioar\\u0103. Astfel, cristalul nu este doar un emi\\u021b\\u0103tor pasiv, ci un aliat activ \\u00een procesul de armonizare.\"}},{\"id\":\"mO1QQyHCrg\",\"type\":\"paragraph\",\"data\":{\"text\":\"Orgoni personaliza\\u021bi \\u2013 c\\u00e2nd crea\\u021bia devine ritual de conectare\"}},{\"id\":\"pX4subrlgG\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare fiin\\u021b\\u0103 are un c\\u00e2mp unic, o vibra\\u021bie proprie \\u0219i o chemare interioar\\u0103. De aceea, orgonii personaliza\\u021bi nu sunt simple obiecte energetice \\u2013 ci extensii ale sufletului celui care \\u00eel va primi. Procesul \\u00eencepe cu o conectare profund\\u0103 la energia persoanei: uneori printr-un mesaj, alteori doar printr-un nume sau o fotografie. Din aceast\\u0103 conexiune se contureaz\\u0103 alegerea materialelor \\u2013 metalele care r\\u0103spund cel mai bine vibra\\u021biei sale, cristalele de care are nevoie, plantele potrivite \\u0219i formele geometrice ce-i vor sus\\u021bine evolu\\u021bia.\"}},{\"id\":\"UJnk-NmzuW\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare orgon este creat \\u00een spa\\u021biu sacru, cu rug\\u0103ciune, cu chemarea ghizilor \\u0219i cu o canalizare atent\\u0103 a frecven\\u021belor potrivite. Inten\\u021bia nu este doar rostit\\u0103, ci tr\\u0103it\\u0103 \\u2013 sim\\u021bit\\u0103 \\u00een palme, \\u00een respira\\u021bie, \\u00een inim\\u0103. Uneori, orgonul \\u201espune\\u201d ce are nevoie: un strat \\u00een plus, un simbol anume, un anumit inel. Alteori, vrea doar s\\u0103 asculte o mantr\\u0103. \\u00cen astfel de momente, devine clar c\\u0103 nu noi cre\\u0103m orgonul, ci c\\u0103 el se na\\u0219te prin noi.\"}},{\"id\":\"dENg0tOa8H\",\"type\":\"paragraph\",\"data\":{\"text\":\"Atunci c\\u00e2nd ajunge la destinatar, orgonul se face sim\\u021bit. Poate fi o senza\\u021bie de c\\u0103ldur\\u0103, o lini\\u0219te care se a\\u0219terne \\u00een camer\\u0103 sau un vis profund \\u00een prima noapte. Mul\\u021bi spun c\\u0103 \\u00eel \\u201eaud\\u201d sau c\\u0103 simt. Asta pentru c\\u0103 un orgon creat cu suflet e mai mult dec\\u00e2t un obiect \\u2013 e o fiin\\u021b\\u0103 vie, o punte \\u00eentre cer, p\\u0103m\\u00e2nt \\u0219i om.\"}},{\"id\":\"gNo0OW2lVl\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/pJ5a2Hfj2Hw6qWprXrsgs2sS3psiNNxxy0CJvKpb.png\"}}},{\"id\":\"FH1vmEurZo\",\"type\":\"paragraph\",\"data\":{\"text\":\"Beneficiile orgonilor\"}},{\"id\":\"NNwm5pV_tl\",\"type\":\"paragraph\",\"data\":{\"text\":\"Printre beneficiile resim\\u021bite de cei care \\u00eei folosesc se num\\u0103r\\u0103:\"}},{\"id\":\"ULV64XXMlr\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Protec\\u021bie energetic\\u0103 \\u00eempotriva radia\\u021biilor electromagnetice, stresului colectiv \\u0219i formelor de g\\u00e2nd stagnante.\"}},{\"id\":\"qINdWhoGL9\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Purificarea spa\\u021biului \\u2013 sus\\u021bine cur\\u0103\\u021barea vibra\\u021bional\\u0103 a camerei \\u00een care este a\\u0219ezat, aduc\\u00e2nd claritate \\u0219i prospe\\u021bime.\"}},{\"id\":\"W8KBOe-Xxg\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Sprijin emo\\u021bional \\u2013 ofer\\u0103 un c\\u00e2mp stabil, calm \\u0219i con\\u021bin\\u0103tor \\u00een perioade de anxietate, agita\\u021bie sau transform\\u0103ri interioare.\"}},{\"id\":\"hC-DyZiVeu\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Activarea intui\\u021biei \\u2013 faciliteaz\\u0103 conexiunea cu vocea interioar\\u0103, visele, viziunile \\u0219i ghidarea subtil\\u0103.\"}},{\"id\":\"vgviT8pjL2\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Sus\\u021binerea proceselor de vindecare \\u2013 amplific\\u0103 lucrul terapeutic, introspec\\u021biile \\u0219i medita\\u021biile, aduc\\u00e2nd o energie de sus\\u021binere bl\\u00e2nd\\u0103.\"}},{\"id\":\"vztvnG4GOl\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Reechilibrare a corpului energetic \\u2013 favorizeaz\\u0103 curgerea energiei prin chakre \\u0219i meridiane, dizolv\\u00e2nd blocaje.\"}},{\"id\":\"waGbDPKHsO\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Reconectare cu natura \\u2013 datorit\\u0103 componentelor vegetale \\u0219i a ADN-ului plantelor, orgonii sus\\u021bin rela\\u021bia subtil\\u0103 cu regnul vegetal \\u0219i cu p\\u0103m\\u00e2ntul viu.\"}},{\"id\":\"6ddACeDPrv\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Stabilizarea spa\\u021biului \\u2013 aduce o senza\\u021bie de \\u201eacas\\u0103\\u201d, de ancorare, de protec\\u021bie \\u00een spa\\u021biul fizic.\"}},{\"id\":\"qRSYSR3TFP\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;Amplificarea inten\\u021biilor personale \\u2013 cristalele programate din interiorul orgonului ac\\u021bioneaz\\u0103 ca purt\\u0103tori de mesaj, sus\\u021bin\\u00e2nd manifestarea con\\u0219tient\\u0103.\"}},{\"id\":\"5vzUQ5F6uy\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/ONoRojHQgIpkyU9MG7ExNEkRL1VKElMTiwG51qrQ.png\"}}},{\"id\":\"aNRGhnNWZ7\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cum s\\u0103 lucrezi cu un orgon: ghid de utilizare con\\u0219tient\\u0103\"}},{\"id\":\"o_1UaAMQqi\",\"type\":\"paragraph\",\"data\":{\"text\":\"Orgonul este mai mult dec\\u00e2t un obiect \\u2013 este o prezen\\u021b\\u0103 energetic\\u0103 vie, creat\\u0103 s\\u0103 te sus\\u021bin\\u0103 exact acolo unde e\\u0219ti. De\\u0219i poate fi a\\u0219ezat oriunde \\u00een spa\\u021biu, recomand\\u0103m s\\u0103 fie plasat acolo unde petreci cel mai mult timp: \\u00een dormitor, pentru regenerare, somn profund \\u0219i echilibrare emo\\u021bional\\u0103, sau \\u00een spa\\u021biul de lucru, pentru focus, claritate \\u0219i protec\\u021bie.\"}},{\"id\":\"P0UIUdklBb\",\"type\":\"paragraph\",\"data\":{\"text\":\"Conectarea cu el se produce adesea \\u00een mod spontan \\u2013 prin simpla atingere, printr-un impuls interior sau o stare de lini\\u0219te care se instaleaz\\u0103. \\u00cel po\\u021bi \\u021bine \\u00een palme, \\u00eel po\\u021bi apropia de inim\\u0103 sau po\\u021bi pur \\u0219i simplu s\\u0103 stai \\u00een prezen\\u021ba lui atunci c\\u00e2nd meditezi, te rogi sau reflectezi. Nu este un instrument care \\u201elucreaz\\u0103 pentru tine\\u201d, ci unul care te \\u00eenso\\u021be\\u0219te cu bl\\u00e2nde\\u021be, oglindindu-\\u021bi procesele \\u0219i amplific\\u00e2ndu-\\u021bi inten\\u021biile.\"}},{\"id\":\"2kCcbk2Wo5\",\"type\":\"paragraph\",\"data\":{\"text\":\"Poate fi cur\\u0103\\u021bat u\\u0219or, \\u00een moduri simple \\u0219i intuitive: sub jet de ap\\u0103, cu o inten\\u021bie clar\\u0103 de purificare, prin sunet (boluri, clopo\\u021bei, mantre), prin contactul cu p\\u0103m\\u00e2ntul sau cu lumina soarelui \\u0219i a lunii. Nu exist\\u0103 o regul\\u0103 strict\\u0103 \\u2013 las\\u0103-\\u021bi intui\\u021bia s\\u0103-\\u021bi arate ce i se potrive\\u0219te.\"}},{\"id\":\"80c58KTFqR\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ascult\\u0103-l. Uneori va cere s\\u0103 fie mutat, re\\u00eemprosp\\u0103tat sau doar \\u021binut aproape pentru o vreme. Fiecare interac\\u021biune cu el este un act de prezen\\u021b\\u0103.\"}},{\"id\":\"IThwaIyuIs\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dac\\u0103 ai sim\\u021bit chemarea, dac\\u0103 rezonezi cu aceste frecven\\u021be \\u0219i sim\\u021bi c\\u0103 un astfel de dispozitiv ar putea face parte din c\\u0103l\\u0103toria ta, ne po\\u021bi contacta cu \\u00eencredere:\"}},{\"id\":\"vVSQqQK-7-\",\"type\":\"paragraph\",\"data\":{\"text\":\"La num\\u0103rul de telefon: 0753645442&nbsp;\"}},{\"id\":\"ynB0oVpQCa\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pe WhatsApp:&nbsp;\"}},{\"id\":\"aZJdKjydJ-\",\"type\":\"paragraph\",\"data\":{\"text\":\"Sau pe e-mail: asociatialotusretreat@gmail.com\"}},{\"id\":\"1jBxoTR-qV\",\"type\":\"paragraph\",\"data\":{\"text\":\"Te a\\u0219tept\\u0103m cu inima deschis\\u0103, gata s\\u0103 co-cre\\u0103m \\u00eempreun\\u0103 un orgon care s\\u0103 te sus\\u021bin\\u0103 exact acolo unde e\\u0219ti.\"}},{\"id\":\"4vHHdUIdMe\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/YhUvXKf6xnrgqNLmTExrZbKJD44EwfEvOLye7kCv.png\"}}}],\"version\":\"2.31.0-rc.7\"}', 3, 'Asociatia Lotus Retreat', '2025-06-08 22:48:07', '2025-06-09 05:34:21'),
(12, 'Povestea Centrului Calea Luminii', 'povestea-centrului-calea-luminii-6846137d5bac0', '<p>Un loc unde trupul, mintea și sufletul se regăsesc – Viziunea unui centru de vindecare născut din iubire</p>', 'posts/preview_images/OYgz2txjJlnHfCxlMfL0kfcQNiHmi7pSAzAGquEH.jpg', '{\"time\":1749449687033,\"blocks\":[{\"id\":\"ln6fezf99E\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00cen inima noastr\\u0103, to\\u021bi purt\\u0103m un dor nespus de a ne reconecta cu esen\\u021ba divin\\u0103, cu iubirea necondi\\u021bionat\\u0103 a lui Dumnezeu.\"}},{\"id\":\"XpuP3cb2_o\",\"type\":\"paragraph\",\"data\":{\"text\":\"Din aceast\\u0103 dorin\\u021b\\u0103 profund\\u0103 s-a n\\u0103scut Centrul Calea Luminii \\u2013 un loc sacru dedicat rug\\u0103ciunii inimii, meditatiei, iubirii \\u0219i \\u00een\\u0103l\\u021b\\u0103rii con\\u0219tiin\\u021bei. Credem c\\u0103, atunci c\\u00e2nd ne deschidem inimile \\u0219i c\\u0103ut\\u0103m conexiunea cu divinitatea, miracolele se vor \\u00eent\\u00e2mpla pentru fiecare dintre noi.\"}},{\"id\":\"FdlWp8GCKN\",\"type\":\"paragraph\",\"data\":{\"text\":\"Totul a \\u00eenceput cu o chemare t\\u0103cut\\u0103, dar puternic\\u0103. O voce interioar\\u0103 care spunea: \\u201eE timpul s\\u0103 creezi un loc unde oamenii s\\u0103-\\u0219i reg\\u0103seasc\\u0103 lumina. Un loc unde Dumnezeu s\\u0103 se poat\\u0103 manifesta prin iubire, prin unitate, prin eliberare, prin vindecare, prin comuniune.\\u201d Aceast\\u0103 voce nu era doar o idee \\u2013 era un mesaj venit dintr-un spa\\u021biu profund, divin. \\u0218i \\u00een inima noastra am \\u0219tiut: acesta este CALEA!\"}},{\"id\":\"UvsJryqz5B\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am primit viziunea unui centru construit \\u00een forma Cubului lui Metatron, ghidat de energia lui Isus \\u2013 o structur\\u0103 a geometriei sacre \\u00een care, fiecare suflet care p\\u0103\\u0219e\\u0219te, s\\u0103 simt\\u0103 pace, vindecare \\u0219i reintoarcere la esenta divina. Astfel, Calea Luminii prinde via\\u021b\\u0103 ca o oaz\\u0103 de iubire \\u0219i de lumin\\u0103, un sanctuar pentru suflet.\"}},{\"id\":\"5IXcFxX8zd\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ce se va \\u00eent\\u00e2mpla \\u00een acest centru?\"}},{\"id\":\"pJlUVBnb8P\",\"type\":\"paragraph\",\"data\":{\"text\":\"Centrul reprezinta at\\u00e2t un spa\\u021biu fizic, c\\u00e2t si un sanctuar al credin\\u021bei, al iubirii \\u0219i al crea\\u021biei. Aici, rug\\u0103ciunea inimii si meditatia, creaza momente sacre de comuniune cu Divinitatea, care aprofundeaza conexiunea spiritual\\u0103 \\u0219i deschid inima pentru a primi iubirea ce ne \\u00eenconjoar\\u0103.\"}},{\"id\":\"3IvzNbV0JG\",\"type\":\"paragraph\",\"data\":{\"text\":\"Copiii vor descoperi bucuria crea\\u021biei prin pictur\\u0103, muzic\\u0103, modelaj, dans \\u2013 activit\\u0103\\u021bi prin care \\u00ee\\u0219i exprim\\u0103 darurile \\u0219i \\u00ee\\u0219i dezvolt\\u0103 \\u00eencrederea, imagina\\u021bia \\u0219i valoarea interioar\\u0103.\"}},{\"id\":\"Zpu8Qz0-qJ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Adul\\u021bii vor reg\\u0103si bucuria jocului \\u0219i a exprim\\u0103rii autentice prin tabere de crea\\u021bie, activ\\u0103ri si curatari energetice, ateliere spirituale, vindecari prin sunete (handpan, boluri de cristal si tibetane si alte instrumente)  b\\u0103i cu ghea\\u021b\\u0103, mers pe c\\u0103rbuni, acupunctur\\u0103 si masaj, rug\\u0103ciune, meditatie \\u0219i reflec\\u021bie.\"}},{\"id\":\"tB_BF3b6jU\",\"type\":\"paragraph\",\"data\":{\"text\":\"Familii \\u00eentregi vor sim\\u021bi c\\u0103 apar\\u021bin unei comunit\\u0103\\u021bi vii, iubitoare, \\u00een care se sus\\u021bin reciproc \\u00een procesul de vindecare, eliberare \\u0219i trezire.\"}},{\"id\":\"fIhbO4xncJ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Aici, in cadrul atelierelor crea\\u021bia devine o form\\u0103 de introspectie a propriului sine, iar fiecare activitate este o poart\\u0103 spre lumin\\u0103 \\u0219i reg\\u0103sire.\"}},{\"id\":\"tQ90YJXw3u\",\"type\":\"paragraph\",\"data\":{\"text\":\"De ce facem asta?\"}},{\"id\":\"TSQgRCG7wT\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru c\\u0103 sim\\u021bim, ca mul\\u021bi dintre voi, dorul de acas\\u0103, dorul de Dumnezeu.\"}},{\"id\":\"dPeu1TOQEo\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru c\\u0103 vrem s\\u0103 oferim copiilor si adultilor un loc \\u00een care s\\u0103-\\u0219i aminteasc\\u0103 cine sunt.\"}},{\"id\":\"0LxUyfPfqZ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru c\\u0103 iubirea poate vindeca tot ce lumea a uitat.\"}},{\"id\":\"P2ONEkS6pM\",\"type\":\"paragraph\",\"data\":{\"text\":\"Calea Luminii este \\u0219i o familie de suflete unite prin acelea\\u0219i valori:\"}},{\"id\":\"p67jPRC-vc\",\"type\":\"paragraph\",\"data\":{\"text\":\"- iubirea necondi\\u021bionat\\u0103\"}},{\"id\":\"UpARGsYown\",\"type\":\"paragraph\",\"data\":{\"text\":\"- credin\\u021ba \\u00een puterea divin\\u0103\"}},{\"id\":\"ELk4OujXih\",\"type\":\"paragraph\",\"data\":{\"text\":\"- dorin\\u021ba de a tr\\u0103i \\u00een armonie cu noi \\u00een\\u0219ine \\u0219i \\u00een unitate cu semenii no\\u0219tri&nbsp;\"}},{\"id\":\"daUgx-jx3s\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare suflet care ajunge aici este \\u00eent\\u00e2mpinat cu bl\\u00e2nde\\u021be, respect, iubire \\u0219i acceptare \\u2013 indiferent de credin\\u021be sau de drum.\"}},{\"id\":\"dgT8l89LrW\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare pas este ghidat de lumina lui Dumnezeu, iar fiecare activitate are scopul de a \\u00een\\u0103l\\u021ba sufletul \\u0219i de a aduce mai mult\\u0103 lumin\\u0103 \\u00een lume.\"}},{\"id\":\"WNjLq4pkb5\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cine suntem noi, fondatorii Centrului Calea Luminii\"}},{\"id\":\"LJsbEvrDfi\",\"type\":\"paragraph\",\"data\":{\"text\":\"George, suflet puternic, tata, facilitator energetic, punte \\u00eentre oameni \\u0219i spa\\u021bii sacre de crea\\u021bie; darul meu este acela de a crea spa\\u021bii vii de conexiune, transformare \\u0219i inspira\\u021bie \\u2013 prin art\\u0103, cuv\\u00e2nt, sunet, energie, t\\u0103cere \\u0219i prezen\\u021b\\u0103.\"}},{\"id\":\"1qoTe0xvLY\",\"type\":\"paragraph\",\"data\":{\"text\":\"Sandra, suflet bl\\u00e2nd, mam\\u0103, terapeut, creator si facilitator de meditatii ghidate si ghid al de taberelor de creatie.\"}},{\"id\":\"SwlOhpC_WS\",\"type\":\"paragraph\",\"data\":{\"text\":\"Al\\u0103turi de noi, pas cu pas, au venit al\\u021bi oameni minuna\\u021bi, uni\\u021bi prin aceea\\u0219i chemare. Toti suntem c\\u0103l\\u0103uzi\\u021bi de Dumnezeu \\u00een fiecare decizie, \\u00een fiecare plan \\u0219i \\u00een fiecare z\\u00e2mbet pe care \\u00eel oferim celor ce vin. Avem credin\\u021ba c\\u0103 Dumnezeu este al\\u0103turi de noi. Daca simti aceeasi chemarea, esti binevenit in misiunea noastra.\"}},{\"id\":\"rbhHr_Uq64\",\"type\":\"paragraph\",\"data\":{\"text\":\"Te chem\\u0103m al\\u0103turi de noi\"}},{\"id\":\"FCdY9G1M30\",\"type\":\"paragraph\",\"data\":{\"text\":\"Sigur nu e intamplator faptul ca mesajul nostru ti-a deschis  inima. Aceasta viziune prinde forma cu ajutorul oamenilor ca tine - care simt, contribuie si cred intr-o lume in care iubirea vindeca.\"}},{\"id\":\"Tf5hpQlamp\",\"type\":\"paragraph\",\"data\":{\"text\":\"Poate \\u0219i tu faci parte din aceast\\u0103 misiune divin\\u0103, pe care o poti sustine astfel:\"}},{\"id\":\"SilIbyH3gD\",\"type\":\"paragraph\",\"data\":{\"text\":\"1. Contribu\\u021bii financiare: \"}},{\"id\":\"QvSQCDFs8r\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ajut\\u0103-ne s\\u0103 achizi\\u021bion\\u0103m terenul, s\\u0103 construim \\u0219i s\\u0103 dot\\u0103m centrul, dar \\u0219i s\\u0103 sus\\u021binem activit\\u0103\\u021bile noastre continue.\"}},{\"id\":\"gURvZ_V6UD\",\"type\":\"paragraph\",\"data\":{\"text\":\" Nume:          Asociatia Lotus Retreat \"}},{\"id\":\"wIvGYmbc97\",\"type\":\"paragraph\",\"data\":{\"text\":\"&nbsp;Cont Lei:      RO61BTRLRONCRT0CS4431102   (descriere plata:  donatie in scopul asociatiei )\"}},{\"id\":\"__CHldYcg9\",\"type\":\"paragraph\",\"data\":{\"text\":\"&nbsp;Cont Euro:   RO35BTRLEURCRT0CS4431101     (descriere plata:  donatie in scopul asociatiei ) \"}},{\"id\":\"sgDUI7FIva\",\"type\":\"paragraph\",\"data\":{\"text\":\"&nbsp;Cont GBP:    RO06BTRLGBPCRT0CS4431101      (descriere plata:  donatie in scopul asociatiei )\"}},{\"id\":\"JkrXroBqh-\",\"type\":\"paragraph\",\"data\":{\"text\":\"(men\\u021bioneaz\\u0103 \\u00een descrierea pl\\u0103\\u021bii: \\u201cdona\\u021bie \\u00een scopul asocia\\u021biei\\u201d)\"}},{\"id\":\"BKm2WsFbIA\",\"type\":\"paragraph\",\"data\":{\"text\":\"Po\\u021bi redirec\\u021biona 3,5% din impozitul pe venit c\\u0103tre noi \\u2013 f\\u0103r\\u0103 niciun cost pentru tine. Este un gest simplu care poate avea un impact profund.\"}},{\"id\":\"xyg3gF6JWC\",\"type\":\"paragraph\",\"data\":{\"text\":\"<a href=\\\"https:\\/\\/formular230.ro\\/lotus-retreat\\\">https:\\/\\/formular230.ro\\/lotus-retreat<\\/a>\"}},{\"id\":\"khdn6nvyv5\",\"type\":\"paragraph\",\"data\":{\"text\":\"2. Achizi\\u021bioneaz\\u0103 produsele noastre:  \"}},{\"id\":\"GgyB4AdGSi\",\"type\":\"paragraph\",\"data\":{\"text\":\"Sus\\u021bine-ne aleg\\u00e2nd produse create cu iubire, rug\\u0103ciune \\u0219i inten\\u021bie vindec\\u0103toare \\u2013 orgoni, crea\\u021bii energetice, artefacte lucrate manual. Fiecare obiect este o ancor\\u0103 de lumin\\u0103 \\u0219i parte din misiunea noastr\\u0103.\"}},{\"id\":\"p1-z4nKbKC\",\"type\":\"paragraph\",\"data\":{\"text\":\"3. Dona\\u021bii \\u00een obiecte:\"}},{\"id\":\"fnoXOKiEKL\",\"type\":\"paragraph\",\"data\":{\"text\":\" Ne sunt de mare ajutor materiale de construc\\u021bie, unelte, mobilier, rechizite creative \\u0219i orice resurs\\u0103 util\\u0103 \\u00een amenajarea centrului \\u0219i desf\\u0103\\u0219urarea taberelor.\"}},{\"id\":\"eWjEBp5OZJ\",\"type\":\"paragraph\",\"data\":{\"text\":\"4. Voluntariat specializat \\u0219i implicare activ\\u0103:\"}},{\"id\":\"H5vk3OY-j8\",\"type\":\"paragraph\",\"data\":{\"text\":\"Po\\u021bi contribui oferindu-\\u021bi timpul \\u0219i cuno\\u0219tin\\u021bele, \\u00een func\\u021bie de ce \\u021bi-e aproape sufletului:\"}},{\"id\":\"AauLV1pjrT\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;suport juridic \\u0219i legislativ\"}},{\"id\":\"BDtNtGgHh8\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;scriere sau coordonare proiecte cu finan\\u021bare (na\\u021bionale sau europene)\"}},{\"id\":\"Um6D9-B01W\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;promovare \\u0219i atragere de fonduri\"}},{\"id\":\"3gjzDLeJLP\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;facilitare de terapii \\u0219i ateliere\"}},{\"id\":\"BRiKTkN-4u\",\"type\":\"paragraph\",\"data\":{\"text\":\" &nbsp;&nbsp;&nbsp;\\u2022&nbsp;&nbsp;&nbsp;&nbsp;ajutor fizic la construirea \\u0219i organizarea spa\\u021biului\"}},{\"id\":\"-AnXQi8BiP\",\"type\":\"paragraph\",\"data\":{\"text\":\"5. Distribuie mai departe mesajul nostru:\"}},{\"id\":\"mRU4GlNLri\",\"type\":\"paragraph\",\"data\":{\"text\":\"Un simplu share poate ajunge exact la sufletul preg\\u0103tit s\\u0103 sus\\u021bin\\u0103 sau s\\u0103 primeasc\\u0103. Fii mesagerul acestei viziuni.\"}},{\"id\":\"p0qbDv2aqZ\",\"type\":\"paragraph\",\"data\":{\"text\":\"6. Sus\\u021bine-ne prin rug\\u0103ciune:\"}},{\"id\":\"fSzjvxhx0o\",\"type\":\"paragraph\",\"data\":{\"text\":\"Roag\\u0103-te pentru claritate \\u00een viziune, protec\\u021bie divin\\u0103, armonie \\u00een echip\\u0103 \\u0219i ca acest centru s\\u0103 se nasc\\u0103 \\u00een deplin\\u0103 r\\u00e2nduial\\u0103 divin\\u0103.\"}},{\"id\":\"XXnCq4Ogxj\",\"type\":\"paragraph\",\"data\":{\"text\":\"7. Sponsoriz\\u0103ri \\u0219i parteneriate:\"}},{\"id\":\"_wdnrYdDnI\",\"type\":\"paragraph\",\"data\":{\"text\":\"Firmele pot oferi sponsoriz\\u0103ri pentru proiectele sau evenimentele noastre. Dac\\u0103 reprezin\\u021bi o companie \\u0219i rezonezi cu viziunea noastr\\u0103, hai s\\u0103 construim \\u00eempreun\\u0103!\"}},{\"id\":\"nVBcu4F-KV\",\"type\":\"paragraph\",\"data\":{\"text\":\"Orice form\\u0103 de ajutor conteaz\\u0103 si fiecare contributie este apreciata si va fi recompensata. Dumnezeu lucreaz\\u0103 prin oameni. Poate tu e\\u0219ti r\\u0103spunsul unei rug\\u0103ciuni.\"}},{\"id\":\"HGPWykcNEJ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Credem \\u00eentr-o lume \\u00een care iubirea vindec\\u0103, intr-o lume \\u00een care copiii z\\u00e2mbesc \\u0219i sufletele se \\u00eent\\u00e2lnesc \\u00een adev\\u0103r, intr-o lume \\u00een care oamenii \\u00ee\\u0219i amintesc propria esenta divina.\"}},{\"id\":\"jnBMZ9K-h3\",\"type\":\"paragraph\",\"data\":{\"text\":\"Te invit\\u0103m s\\u0103 fii parte din aceast\\u0103 Misiune.\"}},{\"id\":\"CPRcJxtENa\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cu iubire \\u0219i recuno\\u0219tin\\u021b\\u0103,\"}},{\"id\":\"rIYY6YaCsw\",\"type\":\"paragraph\",\"data\":{\"text\":\"George, Sandra &amp; echipa Calea Luminii\"}}],\"version\":\"2.31.0-rc.7\"}', 1, 'Asociatia Lotus Retreat', '2025-06-08 22:49:33', '2025-06-09 06:14:47');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `preview_image`, `description`, `order`, `created_by`, `created_at`, `updated_at`) VALUES
(13, '\"Ce înseamnă sa fii un părinte model\"', 'ce-inseamna-sa-fii-un-parinte-model-684613c8797c8', '<p>Nimeni nu te pregate...</p>', 'posts/preview_images/yAEV4DI7bWLAO8MYV7u9uRCgsAQEY0GtLTKhXtAS.jpg', '{\"time\":1749447478965,\"blocks\":[{\"id\":\"ZlLljtlfsu\",\"type\":\"paragraph\",\"data\":{\"text\":\"Nimeni nu te preg\\u0103te\\u0219te cu adev\\u0103rat pentru momentul \\u00een care devii p\\u0103rinte. Po\\u021bi citi c\\u0103r\\u021bi, po\\u021bi merge la cursuri, po\\u021bi primi sute de sfaturi\\u2026 dar c\\u00e2nd \\u00ee\\u021bi \\u021bii copilul \\u00een bra\\u021be, lumea \\u00eentreag\\u0103 cap\\u0103t\\u0103 un alt sens. Iar toate teoriile par s\\u0103 se dizolve \\u00een prezen\\u021ba acelui suflet care te prive\\u0219te.\"}},{\"id\":\"goMRQS30gt\",\"type\":\"paragraph\",\"data\":{\"text\":\"        Pentru noi, a fi p\\u0103rin\\u021bi a devenit nu doar o responsabilitate, ci o cale de \\u00eentoarcere spre Sursa Divin\\u0103. \\u00cen fiecare zi, \\u00een mijlocul bucuriilor \\u0219i provoc\\u0103rilor, sim\\u021bim cum suntem chema\\u021bi s\\u0103 iubim mai profund, s\\u0103 ascult\\u0103m mai atent, s\\u0103 fim mai prezen\\u021bi. A fi p\\u0103rinte ne-a \\u00eenv\\u0103\\u021bat s\\u0103 cobor\\u00e2m din minte \\u00een inim\\u0103, s\\u0103 renun\\u021b\\u0103m la control \\u0219i s\\u0103 ne deschidem spre \\u00eencredere.\"}},{\"id\":\"u3O_G03eB7\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Ne-am rugat. Am t\\u0103cut. Ne-am l\\u0103sat c\\u0103l\\u0103uzi\\u021bi. \\u00cen multe momente, ne-am a\\u0219ezat \\u00eempreun\\u0103 \\u0219i L-am chemat pe Iisus \\u00een mijlocul familiei noastre. Nu ca pe o figur\\u0103 religioas\\u0103, ci ca pe o prezen\\u021b\\u0103 vie, bl\\u00e2nd\\u0103 \\u0219i clar\\u0103, care ne \\u00eenva\\u021b\\u0103 cum s\\u0103 iubim, cum s\\u0103 iert\\u0103m \\u0219i cum s\\u0103 fim p\\u0103rin\\u021bi din adev\\u0103r, nu din programare.\"}},{\"id\":\"IUE2hCO05l\",\"type\":\"paragraph\",\"data\":{\"text\":\"       \\u0218i totu\\u0219i, \\u00een acest drum sacru, ne-am lovit adesea de o realitate puternic\\u0103: a\\u0219tept\\u0103rile societ\\u0103\\u021bii. Ce \\u00eenseamn\\u0103, de fapt, s\\u0103 fii un \\u201ep\\u0103rinte bun\\u201d? S\\u0103 urmezi regulile impuse din exterior sau s\\u0103 ascul\\u021bi vocea interioar\\u0103? S\\u0103-\\u021bi modelezi copilul sau s\\u0103-l \\u00eenso\\u021be\\u0219ti \\u00een drumul lui c\\u0103tre sine?\"}},{\"id\":\"Cuz1OZu_i1\",\"type\":\"paragraph\",\"data\":{\"text\":\"      A\\u0219a a ap\\u0103rut \\u00eentrebarea care ne-a reconfigurat complet parcursul:\"}},{\"id\":\"wEW9H52CK4\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cum ar fi dac\\u0103 L-am pune pe Dumnezeu \\u00een centrul felului \\u00een care ne cre\\u0219tem copilul?\"}},{\"id\":\"Z_LB9wHFoK\",\"type\":\"paragraph\",\"data\":{\"text\":\"Nu ca o autoritate care impune, ci ca o surs\\u0103 vie de iubire, r\\u0103bdare, bl\\u00e2nde\\u021be \\u0219i adev\\u0103r.\"}},{\"id\":\"mz3Fk_L_CG\",\"type\":\"paragraph\",\"data\":{\"text\":\"       \\u00cen acest articol, \\u00eemp\\u0103rt\\u0103\\u0219im din c\\u0103l\\u0103toria noastr\\u0103: ce ne cere societatea, ce tr\\u0103im noi \\u00een realitate \\u0219i cum am ales s\\u0103 aducem \\u00een inima familiei noastre rug\\u0103ciunea, ghidarea divin\\u0103 \\u0219i prezen\\u021ba lui Iisus ca lumin\\u0103 pentru pa\\u0219ii no\\u0219tri de p\\u0103rin\\u021bi.\"}},{\"id\":\"nBz_AsLLHP\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Atunci c\\u00e2nd devii p\\u0103rinte, nu prime\\u0219ti doar un copil \\u00een bra\\u021be, ci \\u0219i o list\\u0103 lung\\u0103 de a\\u0219tept\\u0103ri \\u0219i roluri predefinite. F\\u0103r\\u0103 s\\u0103 ne d\\u0103m seama, ne trezim \\u00een mijlocul unei scene \\u00een care fiecare are deja un costum de purtat, un scenariu de urmat.\"}},{\"id\":\"e_-Ugv5kx5\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Pentru mam\\u0103, rolul este clar: s\\u0103 fie perfect\\u0103. Mereu prezent\\u0103, mereu calm\\u0103, mereu preg\\u0103tit\\u0103 s\\u0103 sacrifice tot \\u2013 somnul, cariera, nevoile personale \\u2013 de dragul copilului. Dac\\u0103 obose\\u0219te sau are nevoie de spa\\u021biu, este considerat\\u0103 egoist\\u0103. Dac\\u0103 pl\\u00e2nge sau se enerveaz\\u0103, este \\u201einstabil\\u0103\\u201d. Dac\\u0103 \\u00eendr\\u0103zne\\u0219te s\\u0103 cear\\u0103 ajutor, este \\u201enepreg\\u0103tit\\u0103\\u201d.\"}},{\"id\":\"YZ-gubB0XL\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Pentru tat\\u0103, povestea nu este mai bl\\u00e2nd\\u0103. Este \\u201eb\\u0103rbatul casei\\u201d, cel care trebuie s\\u0103 aduc\\u0103 stabilitate, bani, direc\\u021bie. S\\u0103 fie protector, dar \\u0219i disponibil. Puternic, dar \\u0219i empatic. \\u0218i \\u00een acela\\u0219i timp, s\\u0103 nu uite s\\u0103 \\u00ee\\u0219i sus\\u021bin\\u0103 partenera, dar f\\u0103r\\u0103 s\\u0103 devin\\u0103 prea \\u201eemo\\u021bional\\u201d.\"}},{\"id\":\"pP3uDbjgJX\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Dincolo de aceste roluri, sim\\u021bim presiunea t\\u0103cut\\u0103, dar constant\\u0103, a unui mesaj colectiv:\"}},{\"id\":\"tuLSnR_jXb\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2022\\u2060  \\u2060Educa\\u021bi-v\\u0103 copilul \\u201ecum trebuie\\u201d.\"}},{\"id\":\"ihY3FLf5-w\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2022\\u2060  \\u2060Fi\\u021bi p\\u0103rin\\u021bi moderni, dar \\u0219i tradi\\u021bionali. Relaxa\\u021bi, dar responsabili. Flexibili, dar cu autoritate.\"}},{\"id\":\"pfxwuXfWHI\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2022\\u2060  \\u2060\\u0218i mai ales\\u2026 s\\u0103 se vad\\u0103 rezultatele!\"}},{\"id\":\"ziL95on5xW\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Societatea pare s\\u0103 ne \\u00eemping\\u0103 mereu spre control \\u0219i performan\\u021b\\u0103. Copilul trebuie s\\u0103 mearg\\u0103 repede, s\\u0103 vorbeasc\\u0103 repede, s\\u0103 renun\\u021be la suzet\\u0103, la al\\u0103ptat, la ata\\u0219ament. S\\u0103 fie \\u201ecuminte\\u201d, dar nu prea t\\u0103cut. Independent, dar nu distant. Adaptat, dar nu rebel.\"}},{\"id\":\"pfAJ6sTiQ-\",\"type\":\"paragraph\",\"data\":{\"text\":\"       \\u0218i peste toate, vin mesajele subtile, acele \\u00eentreb\\u0103ri lansate cu z\\u00e2mbete politicoase dar care sap\\u0103 \\u00een noi ad\\u00e2nc:\"}},{\"id\":\"OQZOIxkFD6\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2013 \\u201eAi \\u00eenceput diversificarea?\\u201d\"}},{\"id\":\"6uGvSl8mMQ\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2013 \\u201e\\u00cenc\\u0103 al\\u0103ptezi? Nu e cam mare?\\u201d\"}},{\"id\":\"cJr7FdwcPQ\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2013 \\u201eL-ai dus la gr\\u0103di? E important s\\u0103 socializeze.\\u201d\"}},{\"id\":\"4Xq6R71Jad\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2013 \\u201e\\u00cenc\\u0103 nu merge? Copilul vecinei deja alearg\\u0103.\\u201d\"}},{\"id\":\"STbPeE9jPt\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2013 \\u201eNu i-ai pus televizor s\\u0103 se mai lini\\u0219teasc\\u0103 pu\\u021bin?\\u201d\"}},{\"id\":\"7-g8Ds11h_\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Toate aceste \\u00eentreb\\u0103ri vin \\u00een valuri, zi dup\\u0103 zi, p\\u00e2n\\u0103 c\\u00e2nd \\u00eencepem s\\u0103 ne \\u00eendoim de propria intui\\u021bie. S\\u0103 ne compar\\u0103m. S\\u0103 credem c\\u0103 nu facem destul. C\\u0103 nu suntem destul. Dar tocmai \\u00een acest zgomot social, am \\u00eenceput s\\u0103 ne \\u00eentreb\\u0103m:\"}},{\"id\":\"C7UdPtnu8b\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2022\\u2060  \\u2060Unde este Dumnezeu \\u00een toate acestea?\"}},{\"id\":\"Yo8ryDh5y8\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2022\\u2060  \\u2060Unde e rug\\u0103ciunea care aduce lini\\u0219te? Unde e \\u00eencrederea \\u00een ritmul divin al copilului nostru?\"}},{\"id\":\"8DQsCLAO1C\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u2022\\u2060  \\u2060Unde este intuitia sufletului nostru de mam\\u0103 \\u0219i tat\\u0103?\"}},{\"id\":\"1Kcs_GhSOq\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Adev\\u0103rul e c\\u0103 niciun sistem nu poate \\u00eenlocui inima p\\u0103rin\\u021bilor. Niciun plan nu e mai valoros dec\\u00e2t conexiunea vie dintre noi, copil \\u0219i Sursa Divin\\u0103 care ne-a adus \\u00eempreun\\u0103.\"}},{\"id\":\"AD_EtfuGw1\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Dincolo de tot ce \\u201ear trebui\\u201d, exist\\u0103 realitatea noastr\\u0103 \\u2013 vie, imperfect\\u0103 \\u0219i tot mai sincer\\u0103 pe m\\u0103sur\\u0103 ce ne l\\u0103s\\u0103m dezbr\\u0103ca\\u021bi de aparen\\u021be. Adev\\u0103rul e c\\u0103 nu e u\\u0219or.\"}},{\"id\":\"Pf6vZHinDb\",\"type\":\"paragraph\",\"data\":{\"text\":\"Sunt momente \\u00een care suntem obosi\\u021bi, \\u00een care ne punem sub semnul \\u00eentreb\\u0103rii fiecare decizie. Sunt seri \\u00een care sim\\u021bim c\\u0103 am dat tot. \\u0218i sunt zile \\u00een care ne uit\\u0103m unul la cel\\u0103lalt \\u0219i ne \\u00eentreb\\u0103m: Oare ne descurc\\u0103m? Oare facem bine?\"}},{\"id\":\"LGS-wAg7tP\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Dar apoi apare un z\\u00e2mbet. Un gest mic, un oftat lini\\u0219tit \\u00een somn, o m\\u00e2nu\\u021b\\u0103 care ne atinge obrazul. \\u0218i \\u00een acea clip\\u0103, totul se schimb\\u0103. Toat\\u0103 oboseala se tope\\u0219te pentru o secund\\u0103 \\u00een acel z\\u00e2mbet care pare s\\u0103 vin\\u0103 direct din cer. E ca \\u0219i cum Dumnezeu ne-ar atinge prin chipul copilului nostru. Ne umplem de iubire, de sens, de via\\u021b\\u0103. \\u0218i ne amintim de ce suntem aici: nu ca s\\u0103 fim perfec\\u021bi, ci ca s\\u0103 iubim.\"}},{\"id\":\"9WLVFttgnQ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ca s\\u0103 ne \\u00eentoarcem, clip\\u0103 de clip\\u0103, la acea stare \\u00een care inima noastr\\u0103 recunoa\\u0219te divinul din inima lui.\"}},{\"id\":\"rOfmvbV_2r\",\"type\":\"paragraph\",\"data\":{\"text\":\"       A fi p\\u0103rin\\u021bi ne-a dus \\u00eentr-o c\\u0103l\\u0103torie profund\\u0103, nu doar cu copilul, ci cu noi \\u00een\\u0219ine.\"}},{\"id\":\"SL2KKD7Fil\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare criz\\u0103 de pl\\u00e2ns a fost o invita\\u021bie s\\u0103 ne \\u00eentoarcem la propriile noastre r\\u0103ni. Fiecare \\u201enu vreau\\u201d al copilului nostru a fost o oglind\\u0103 pentru acea parte din noi care nu a fost l\\u0103sat\\u0103 s\\u0103 spun\\u0103 \\u201enu\\u201d. Fiecare privire r\\u0103nit\\u0103 ne-a str\\u0103puns direct \\u00een locurile unde noi \\u00een\\u0219ine nu am fost v\\u0103zu\\u021bi.\"}},{\"id\":\"E3w0G4PfjS\",\"type\":\"paragraph\",\"data\":{\"text\":\"       \\u0218i \\u00een acele momente, nu teoria ne-a \\u021binut. Ci rug\\u0103ciunea. Medita\\u021bia. Prezen\\u021ba. Iisus. C\\u00e2nd nu mai \\u0219tiam ce s\\u0103 facem, ne-am pus m\\u00e2inile pe inim\\u0103 \\u0219i am \\u00eentrebat:\"}},{\"id\":\"xYKdeT6ODN\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u201cDoamne, ce vrei s\\u0103 vedem aici? Ce e de vindecat \\u00een noi, prin acest copil?\\u201d \\u0218i r\\u0103spunsurile nu au venit mereu imediat. Dar au venit \\u2013 prin lini\\u0219te, prin revela\\u021bii, prin vise, prin gesturile bl\\u00e2nde ale copilului nostru, care p\\u0103rea uneori s\\u0103 ne aline sufletul mai mult dec\\u00e2t o putea face orice cuv\\u00e2nt.\"}},{\"id\":\"66R1_Tc2l5\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Am \\u00eenv\\u0103\\u021bat c\\u0103 nu e de datoria noastr\\u0103 s\\u0103 \\u201emodel\\u0103m\\u201d copilul dup\\u0103 cum crede lumea c\\u0103 trebuie s\\u0103 fie. Noi nu am venit s\\u0103 cre\\u0219tem un om \\u201ecuminte\\u201d sau \\u201eadaptat\\u201d \\u00een sensul conven\\u021bional. Am venit s\\u0103-l \\u00eenso\\u021bim, s\\u0103-l privim ca pe un suflet complet, viu, care are deja o leg\\u0103tur\\u0103 cu Sursa \\u0219i care \\u0219tie, adesea, mai mult dec\\u00e2t noi.\"}},{\"id\":\"nD96NEDhak\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Am \\u00eenv\\u0103\\u021bat s\\u0103-l ascult\\u0103m cu inima, nu cu filtrele min\\u021bii noastre. S\\u0103 nu-i cerem s\\u0103 fie \\u201ebun\\u201d pentru ca noi s\\u0103 fim lini\\u0219ti\\u021bi. S\\u0103 nu-l gr\\u0103bim s\\u0103 se adapteze la o lume care uneori e rupt\\u0103 de Adev\\u0103r. \\u0218i cel mai important: Am \\u00eenv\\u0103\\u021bat c\\u0103, pentru a-l putea \\u021bine cu bl\\u00e2nde\\u021be \\u00een bra\\u021be, trebuie mai \\u00eent\\u00e2i s\\u0103 ne \\u021binem pe noi \\u00een\\u0219ine cu bl\\u00e2nde\\u021be.\"}},{\"id\":\"ph9h6_mFnO\",\"type\":\"paragraph\",\"data\":{\"text\":\"       C\\u00e2nd apare un copil, nu se sf\\u00e2r\\u0219e\\u0219te nimic \\u2013 ci \\u00eencepe ceva cu totul nou. Nu e o pauz\\u0103 de la cine e\\u0219ti sau ce cau\\u021bi. Din contr\\u0103: copilul devine catalizatorul unei c\\u0103l\\u0103torii mai profunde. Nu te \\u00eenchide spiritual, ci te deschide c\\u0103tre esen\\u021bial.\"}},{\"id\":\"KewdtIXALu\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Ne rug\\u0103m \\u00eempreun\\u0103. C\\u00e2teodat\\u0103 prin cuvinte, alteori \\u00een lini\\u0219te. Uneori aprindem o lum\\u00e2nare, alteori doar st\\u0103m \\u0219i \\u00eei mul\\u021bumim lui Dumnezeu pentru \\u00eenc\\u0103 o zi \\u00een care suntem \\u00eempreun\\u0103. Folosim palo santo, c\\u00e2nt\\u0103m \\u00eempreun\\u0103 la boluri tibetane, respir\\u0103m ad\\u00e2nc \\u0219i ne reamintim c\\u0103 suntem vii.\"}},{\"id\":\"iYdgSrelSJ\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/NUGd4qFNKUa5DXsWJqBAjalmlq3dxmooVvIbpQu3.png\"}}},{\"id\":\"oLN9IBpvXO\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Copilul particip\\u0103. Nu este \\u00een plus. Nu ne \\u00eencurc\\u0103 \\u00een ritualuri, \\u00een retrageri sau \\u00een introspec\\u021bie \\u2013 e parte din ele.\"}},{\"id\":\"jfTLqOE_hX\",\"type\":\"paragraph\",\"data\":{\"text\":\"Nu am \\u00eencetat s\\u0103 c\\u0103l\\u0103torim sau s\\u0103 ne conect\\u0103m cu natura. Urc\\u0103m pe munte, ne adapt\\u0103m. Am ajuns p\\u00e2n\\u0103 pe V\\u00e2rful Omu cu el \\u00een bra\\u021be. A fost solicitant, da \\u2013 dar a fost divin.\"}},{\"id\":\"qtTGdl6GJ4\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Ce am \\u00eenv\\u0103\\u021bat este c\\u0103 nu e nevoie de o lini\\u0219te absolut\\u0103 sau de o retragere perfect\\u0103 pentru a te conecta cu Dumnezeu. E suficient s\\u0103-L invi\\u021bi acolo unde e\\u0219ti. \\u00cen ritmul t\\u0103u, cu inima deschis\\u0103.\"}},{\"id\":\"fOCqx2PL6h\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Ne-am creat ritualuri noi. Ne-am adaptat. Ne-am schimbat. Fa\\u021b\\u0103 de cum am fost crescu\\u021bi, fa\\u021b\\u0103 de cum credeam c\\u0103 vom fi. \\u00cencerc\\u0103m s\\u0103 nu mai reac\\u021bion\\u0103m din fric\\u0103 sau din vina. C\\u00e2nd apare ceva \\u00een neregul\\u0103,  \\u00een loc s\\u0103 ne \\u00eentreb\\u0103m \\u201ece e \\u00een neregul\\u0103 cu el?\\u201d, ne \\u00eentreb\\u0103m cu onestitate: \\u201eCe e dezechilibrat \\u00een noi acum? Ce vrea s\\u0103 ne arate?\\u201d\"}},{\"id\":\"U_taZ_X0pW\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Copiii nu au nevoie de p\\u0103rin\\u021bi perfec\\u021bi. Ci de p\\u0103rin\\u021bi reali, sinceri, conecta\\u021bi. Care \\u00ee\\u0219i cer iertare cu sufletul, nu din reflex. Care spun \\u201ete iubesc\\u201d \\u0219i o simt. Care aleg zi de zi s\\u0103 fie acolo \\u2013 nu ca ideal, ci ca prezen\\u021b\\u0103 vie, uman\\u0103, divin\\u0103.\"}},{\"id\":\"aQL5y8SHRs\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/vEHhU5xV9NzWygNedYK4HFO6KM4qp9uynlnOhhia.png\"}}},{\"id\":\"wKtHA31NRW\",\"type\":\"paragraph\",\"data\":{\"text\":\"       A fi p\\u0103rinte, pentru noi, nu este o piedic\\u0103 \\u00een calea \\u00eent\\u00e2lnirii cu Dumnezeu. Este poate cea mai direct\\u0103 form\\u0103 de \\u00eent\\u00e2lnire.\"}},{\"id\":\"6FKaI4bcRT\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Ne \\u00eentoarcem la \\u00eentreb\\u0103rile cu care am \\u00eenceput: Ce \\u00eenseamn\\u0103 s\\u0103 fii un \\u201ep\\u0103rinte bun\\u201d \\u00een ochii lumii? Dar \\u00een ochii sufletului t\\u0103u?\"}},{\"id\":\"NaYYFj-Ezq\",\"type\":\"paragraph\",\"data\":{\"text\":\"Poate c\\u0103 r\\u0103spunsurile nu sunt fixe, dar se nasc din tr\\u0103irea fiec\\u0103rei zile. Din privirea copilului t\\u0103u. Din felul \\u00een care alegi s\\u0103 fii acolo \\u2013 nu perfect, ci prezent.\"}},{\"id\":\"1qh4QlZ5fY\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Adev\\u0103rul e c\\u0103 nimeni nu e cu adev\\u0103rat preg\\u0103tit pentru momentul \\u00een care devine p\\u0103rinte. Dar poate tocmai \\u00een acest \\u201enepreg\\u0103tit\\u201d st\\u0103 \\u0219i frumuse\\u021bea drumului. Nu e nevoie s\\u0103 \\u0219tii totul, ci doar s\\u0103 fii dispus s\\u0103 \\u00eenve\\u021bi, s\\u0103 te la\\u0219i ghidat \\u0219i s\\u0103 iube\\u0219ti din ce \\u00een ce mai con\\u0219tient.\"}},{\"id\":\"Fc6SgBtcNb\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Pentru noi, a fi p\\u0103rin\\u021bi a devenit o cale de apropiere de Dumnezeu. Cu toate provoc\\u0103rile, cu toate revela\\u021biile, cu toat\\u0103 bucuria de a merge \\u00eempreun\\u0103.\"}},{\"id\":\"UA2YGRBlh-\",\"type\":\"paragraph\",\"data\":{\"text\":\"       Dac\\u0103 acest articol a trezit ceva \\u00een tine, dac\\u0103 te-ai sim\\u021bit v\\u0103zut(\\u0103) sau inspirat(\\u0103), scrie-ne.\"}},{\"id\":\"76ysk9T9e5\",\"type\":\"paragraph\",\"data\":{\"text\":\"Poate nu avem toate r\\u0103spunsurile, dar putem s\\u0103 fim martori unii pentru ceilal\\u021bi.\"}},{\"id\":\"Ttv3xKA0ro\",\"type\":\"paragraph\",\"data\":{\"text\":\"       \\u0218i dac\\u0103 e\\u0219ti acum pe acest drum, \\u00een inima rolului de p\\u0103rinte, \\u00ee\\u021bi trimitem o \\u00eembr\\u0103\\u021bi\\u0219are. E\\u0219ti acolo unde trebuie. Exact a\\u0219a cum e\\u0219ti.\"}},{\"id\":\"Eduskvk0Ak\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":false,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/fCZT130akiwN6b0vooVuNLFu8NlMJTv2ZEu3BtPP.png\"}}}],\"version\":\"2.31.0-rc.7\"}', 4, 'Asociatia Lotus Retreat', '2025-06-08 22:50:48', '2025-06-09 05:37:59'),
(14, 'Mă protejez sau mă închid? Despre rana de respingere si frica de a primi', 'ma-protejez-sau-ma-inchid-despre-rana-de-respingere-si-frica-de-a-primi-684c7eab8d0ab', '<p>Uneori, rana de respingere nu se manifesta doar prin ceilalți… ci prin felul în care noi înșine respingem binele care vine spre noi.&nbsp;</p><p>&nbsp;</p>', 'posts/preview_images/6HCU5pGS4hXufbVQeYI136jL5NJjcQ2k89brNLzF.jpg', '{\"time\":1749843713112,\"blocks\":[{\"id\":\"1d_iyMIcSV\",\"type\":\"paragraph\",\"data\":{\"text\":\"&nbsp; &nbsp; &nbsp; &nbsp; &nbsp;\"}},{\"id\":\"VXB-F1UL1O\",\"type\":\"paragraph\",\"data\":{\"text\":\"&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;Zilele trecute, \\u00een mijlocul unei t\\u0103ceri ad\\u00e2nci, am avut un moment de claritate care m-a str\\u0103fulgerat: r\\u0103ni\\u021bi de at\\u00e2tea ori \\u00een trecut, ajungem uneori s\\u0103 respingem binele \\u00eenainte ca el s\\u0103 apuce s\\u0103 ne ating\\u0103.\"}},{\"id\":\"GM1NixtFpT\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mi-am dat seama c\\u00e2t de subtil func\\u021bioneaz\\u0103 rana de respingere \\u2014 nu doar prin suferin\\u021ba de a fi l\\u0103sat deoparte, ci \\u0219i prin acel impuls incon\\u0219tient de a o lua \\u00eenaintea vie\\u021bii \\u0219i de a spune \\u201enu\\u201d unei iubiri, unei recunoa\\u0219teri, unei ocazii\\u2026 chiar \\u00eenainte ca ele s\\u0103 ne spun\\u0103 \\u201eda\\u201d.\"}},{\"id\":\"4V81wmnh68\",\"type\":\"paragraph\",\"data\":{\"text\":\"Poate ai sim\\u021bit \\u0219i tu, m\\u0103car o dat\\u0103, cum ceva bun se apropia de tine, iar tu \\u2014 aproape f\\u0103r\\u0103 s\\u0103-\\u021bi dai seama \\u2014 ai \\u00eenchis u\\u0219a. Ai \\u00eentors spatele unei oportunit\\u0103\\u021bi, ai respins un compliment, ai fugit de o rela\\u021bie care p\\u0103rea promi\\u021b\\u0103toare. \\u0218i apoi te-ai \\u00eentrebat: \\u201eDe ce am f\\u0103cut asta?\\u201d\"}},{\"id\":\"9jVWhYaky3\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ei bine\\u2026 poate c\\u0103 acel \\u201enu\\u201d nu venea din prezent, ci dintr-o ran\\u0103 veche care doar \\u00eencerca s\\u0103 te protejeze.\"}},{\"id\":\"h0dpSbYbfB\",\"type\":\"paragraph\",\"data\":{\"text\":\"Rana de respingere se formeaz\\u0103, de cele mai multe ori, \\u00een copil\\u0103rie, atunci c\\u00e2nd unul dintre p\\u0103rin\\u021bi (sau o figur\\u0103 important\\u0103 pentru copil) transmite, uneori involuntar, mesajul c\\u0103 nu e\\u0219ti dorit, c\\u0103 deranjezi sau c\\u0103 e\\u0219ti \\u201eprea mult\\u201d sau \\u201eprea pu\\u021bin\\u201d. Poate nu \\u021bi-a spus direct aceste lucruri, dar copilul din tine a sim\\u021bit lipsa de aten\\u021bie, de acceptare, de prezen\\u021b\\u0103, ca pe o form\\u0103 dureroas\\u0103 de respingere a propriei existen\\u021be.\"}},{\"id\":\"wMmpM07pYp\",\"type\":\"paragraph\",\"data\":{\"text\":\"Din punct de vedere psihologic, aceast\\u0103 ran\\u0103 creeaz\\u0103 un mecanism de autoap\\u0103rare: evitarea durerii prin evitarea expunerii. Apare o hipersensibilitate la orice gest, cuv\\u00e2nt sau situa\\u021bie care ar putea sugera c\\u0103 \\u201enu e\\u0219ti suficient\\u201d, c\\u0103 nu ai valoare sau c\\u0103 nu meri\\u021bi iubirea \\u0219i aten\\u021bia celorlal\\u021bi.\"}},{\"id\":\"K0yijQT2P3\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ajun\\u0219i la maturitate, purt\\u0103m aceast\\u0103 ran\\u0103 \\u00een t\\u0103cere, iar ea \\u00eencepe s\\u0103 ne influen\\u021beze aproape fiecare aspect al vie\\u021bii:\"}},{\"id\":\"uAnvVSC1SU\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\t\\u2022\\t\\u00cen rela\\u021bii, ne retragem sau alegem oameni care ne confirm\\u0103 respingerea.\"}},{\"id\":\"hJbNvYe-yP\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\t\\u2022\\t\\u00cen carier\\u0103, ne sabot\\u0103m sau evit\\u0103m s\\u0103 ne facem vizibili.\"}},{\"id\":\"73ab_OACzA\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\t\\u2022\\t\\u00cen fa\\u021ba succesului sau a bucuriei, sim\\u021bim un disconfort inexplicabil \\u2013 ca \\u0219i cum nu avem voie s\\u0103 fim acolo.\"}},{\"id\":\"8cnsDudMmD\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u0218i atunci, f\\u0103r\\u0103 s\\u0103 vrem, \\u00eencepem s\\u0103 respingem exact lucrurile care ar putea s\\u0103 ne vindece. Uneori, binele vine spre noi \\u00een cele mai simple forme: un compliment sincer, o m\\u00e2n\\u0103 \\u00eentins\\u0103, o oportunitate nea\\u0219teptat\\u0103, o persoan\\u0103 care ne vede cu adev\\u0103rat. Dar dac\\u0103 rana de respingere e activ\\u0103, toate acestea pot deveni pericole emo\\u021bionale, nu daruri. De team\\u0103 s\\u0103 nu fim r\\u0103ni\\u021bi din nou, prefer\\u0103m \\u2013 incon\\u0219tient \\u2013 s\\u0103 ne protej\\u0103m. \\u0218i cum facem asta? Prin respingere.\"}},{\"id\":\"Zae_cqXZOc\",\"type\":\"paragraph\",\"data\":{\"text\":\"Refuz\\u0103m invita\\u021bia care ne-ar fi adus bucurie. Minimiz\\u0103m complimentul cu un z\\u00e2mbet jenat: \\u201eLas\\u0103, nu e cine \\u0219tie ce.\\u201d Am\\u00e2n\\u0103m un proiect care ne entuziasmeaz\\u0103. Ne \\u00eendep\\u0103rt\\u0103m de oameni care ne ofer\\u0103 afec\\u021biune sincer\\u0103. \\u0218i apoi, ne spunem: \\u201eNu e momentul\\u201d, \\u201eNu sunt preg\\u0103tit\\u201d, \\u201ePoate nu e pentru mine.\\u201d Dar, \\u00een realitate, poate e doar rana care \\u0219opte\\u0219te: \\u201eMai bine nu sim\\u021bi nimic, dec\\u00e2t s\\u0103 sim\\u021bi din nou durerea respingerii.\\u201d\"}},{\"id\":\"b6APYv_re3\",\"type\":\"paragraph\",\"data\":{\"text\":\"Poate c\\u0103 nici nu \\u021bi-ai dat seama p\\u00e2n\\u0103 acum c\\u0103 faci asta. Pentru c\\u0103 aceste mecanisme sunt subtile, ascunse adesea sub pretexte aparent ra\\u021bionale.\"}},{\"id\":\"QWpuFFhEAU\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dar dac\\u0103 \\u00ee\\u021bi iei un moment sincer cu tine, s-ar putea s\\u0103 recuno\\u0219ti unele dintre aceste semne:\"}},{\"id\":\"UulICfS8g9\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\t\\u2022\\tSpui \\u201enu e pentru mine\\u201d chiar \\u00eenainte s\\u0103 \\u00eencerci sau s\\u0103 dai voie unei experien\\u021be s\\u0103 se desf\\u0103\\u0219oare.\"}},{\"id\":\"UrXZotZHss\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\t\\u2022\\tTe sim\\u021bi u\\u0219or iritat sau \\u00eencepi s\\u0103 devii distant fa\\u021b\\u0103 de oamenii care te apreciaz\\u0103 sincer, f\\u0103r\\u0103 s\\u0103-\\u021bi cear\\u0103 nimic \\u00een schimb.\"}},{\"id\":\"HTtVOML4yC\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\t\\u2022\\t\\u00ce\\u021bi este greu s\\u0103 prime\\u0219ti iubire, sus\\u021binere sau gesturi frumoase \\u2013 te sim\\u021bi inconfortabil, suspect sau \\u201edator\\u201d.\"}},{\"id\":\"ywbdFUV-pQ\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\t\\u2022\\tAi tendin\\u021ba s\\u0103 sabotezi sau s\\u0103 fugi atunci c\\u00e2nd lucrurile merg prea bine \\u2013 ca \\u0219i cum nu po\\u021bi avea \\u00eencredere \\u00een acea stare de bine.\"}},{\"id\":\"ZC7g6zL4_r\",\"type\":\"paragraph\",\"data\":{\"text\":\"Toate acestea nu sunt \\u201egre\\u0219eli\\u201d. Nu sunt dovezi c\\u0103 e ceva \\u00een neregul\\u0103 cu tine. Sunt doar urmele unei dureri care, c\\u00e2ndva, a fost prea mare pentru a fi con\\u021binut\\u0103. \\u0218i care, ast\\u0103zi, \\u00ee\\u021bi cere doar un pic de aten\\u021bie, de \\u00een\\u021belegere, de bl\\u00e2nde\\u021be.\"}},{\"id\":\"AwpwJynwXS\",\"type\":\"paragraph\",\"data\":{\"text\":\"Vindecarea r\\u0103nii de respingere \\u00eencepe cu prezen\\u021b\\u0103. Nu e nevoie s\\u0103 \\u201efaci\\u201d ceva imediat, ci doar s\\u0103 \\u00eenve\\u021bi s\\u0103 r\\u0103m\\u00e2i acolo, cu tine, \\u00een acele momente care alt\\u0103dat\\u0103 te-ar fi f\\u0103cut s\\u0103 te retragi.\"}},{\"id\":\"pyN4g17uuj\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\ud83d\\udccdObserv\\u0103 momentele \\u00een care apare respingerea automat\\u0103. Pot fi multe, uneori subtile: un g\\u00e2nd care te face s\\u0103 refuzi o invita\\u021bie, o senza\\u021bie de disconfort c\\u00e2nd cineva \\u00ee\\u021bi ofer\\u0103 iubire, o nevoie de a te \\u00eenchide tocmai c\\u00e2nd ceva frumos se apropie de tine.\"}},{\"id\":\"694JCQMVjC\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\ud83d\\udccdRespir\\u0103 con\\u0219tient. Inspir\\u0103\\u2026 \\u0219i expir\\u0103 \\u00eencet. Fii cu corpul t\\u0103u. Simte ce se \\u00eent\\u00e2mpl\\u0103 \\u00een piept, \\u00een abdomen, \\u00een respira\\u021bie. Nu judeca. Nu analiza. Doar fii.\"}},{\"id\":\"kPdcgc_tCS\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\ud83d\\udccd\\u0218i apoi, \\u00eentreab\\u0103-te cu bl\\u00e2nde\\u021be: \\u201eCe mi-e fric\\u0103 s\\u0103 simt acum?\\u201d Las\\u0103 r\\u0103spunsul s\\u0103 vin\\u0103 f\\u0103r\\u0103 grab\\u0103. Poate e frica de a fi r\\u0103nit din nou. De a fi v\\u0103zut cu adev\\u0103rat. De a nu fi suficient.\"}},{\"id\":\"WgQilS0ssS\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\ud83d\\udccdIar \\u00een loc s\\u0103 fugi, \\u00eentreab\\u0103-te: \\u201ePot primi acest bine\\u2026 chiar dac\\u0103 simt team\\u0103?\\u201d Aceast\\u0103 \\u00eentrebare nu cere perfec\\u021biune. Nu cere s\\u0103 nu mai doar\\u0103. Cere doar o mic\\u0103 deschidere. At\\u00e2t.\"}},{\"id\":\"YGdrlc5WeQ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dac\\u0103 sim\\u021bi s\\u0103 aprofundezi, am creat o medita\\u021bie ghidat\\u0103 pentru rana de respingere, \\u00een care po\\u021bi practica, \\u00een siguran\\u021b\\u0103, acest proces al deschiderii \\u00een fa\\u021ba binelui.\"}},{\"id\":\"uHhh6zD0J1\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\ud83c\\udf00&nbsp;\"}},{\"id\":\"qyotTkXlkH\",\"type\":\"embed\",\"data\":{\"service\":\"youtube\",\"source\":\"https:\\/\\/www.youtube.com\\/watch?v=zJ6uHM-cQr8\",\"embed\":\"https:\\/\\/www.youtube.com\\/embed\\/zJ6uHM-cQr8\",\"width\":580,\"height\":320,\"caption\":\"\"}},{\"id\":\"_ax7U-iGnt\",\"type\":\"paragraph\",\"data\":{\"text\":\"Poate c\\u0103 nu e u\\u0219or s\\u0103 recuno\\u0219ti c\\u00e2nd respingi ceea ce \\u00ee\\u021bi dore\\u0219ti cel mai mult. Dar e un act de curaj. Pentru c\\u0103 fiecare clip\\u0103 \\u00een care devii con\\u0219tient, fiecare respira\\u021bie \\u00een care alegi s\\u0103 r\\u0103m\\u00e2i, fiecare \\u00eentrebare sincer\\u0103 pe care \\u021bi-o adresezi \\u2014 toate sunt pa\\u0219i spre tine.\"}},{\"id\":\"N0F7yoLS8L\",\"type\":\"paragraph\",\"data\":{\"text\":\"Nu trebuie s\\u0103 \\u201ete vindeci\\u201d \\u00eentr-o zi. E suficient s\\u0103 \\u00eencepi s\\u0103 te \\u00eembl\\u00e2nze\\u0219ti. S\\u0103 nu te mai respingi tu, acolo unde c\\u00e2ndva ai fost respins. S\\u0103-\\u021bi oferi permisiunea de a primi. De a sim\\u021bi. De a merita.\"}},{\"id\":\"Oc9T7fIpeW\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru c\\u0103 da \\u2014 meri\\u021bi s\\u0103 prime\\u0219ti binele. Chiar \\u0219i dac\\u0103 \\u00eenc\\u0103 mai sim\\u021bi team\\u0103. Chiar \\u0219i dac\\u0103 nu \\u0219tii cum s\\u0103-l por\\u021bi. Chiar \\u0219i dac\\u0103 nu l-ai mai primit p\\u00e2n\\u0103 acum.\"}},{\"id\":\"1tKXXz4k8k\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\t\\ud83e\\udd0d Iar dac\\u0103 sim\\u021bi s\\u0103 ne sus\\u021bii misiunea \\u0219i parcursul mai departe, o po\\u021bi face printr-o dona\\u021bie \\u00een contul asocia\\u021biei.&nbsp;\"}},{\"id\":\"Sb0rtWWL7g\",\"type\":\"paragraph\",\"data\":{\"text\":\"Nume:&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Asociatia Lotus Retreat&nbsp;\"}},{\"id\":\"63cTFAUXEQ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cont Lei:&nbsp; &nbsp; &nbsp; RO61BTRLRONCRT0CS4431102&nbsp;&nbsp;&nbsp;\"}},{\"id\":\"vvqWeSQjcD\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cont Euro: &nbsp; RO35BTRLEURCRT0CS4431101&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"}},{\"id\":\"O98DgJkXjq\",\"type\":\"paragraph\",\"data\":{\"text\":\"Cont GBP:&nbsp; &nbsp; RO06BTRLGBPCRT0CS4431101&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;\"}},{\"id\":\"isShpW9MI5\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00ce\\u021bi mul\\u021bumim cu recunostinta pentru sprijin! Iti suntem recunoscatori!&nbsp;\"}}],\"version\":\"2.31.0-rc.7\"}', 5, 'Asociatia Lotus Retreat', '2025-06-13 19:40:27', '2025-06-13 19:41:53'),
(15, 'Cercul celor Cinci: despre orgonul mare și cele patru surori cardinale care susțin spațiul vindecării', 'cercul-celor-cinci-despre-orgonul-mare-si-cele-patru-surori-cardinale-care-sustin-spatiul-vindecarii-6863f5373edb4', '<p>Am adus această structură ultima dată într-un retreat transformational</p>', 'posts/preview_images/RWN0Y5gtil1wpOMwp9msbZ0HHv5UoCGtzmuzK1KX.jpg', '{\"time\":1751546193266,\"blocks\":[{\"id\":\"8U-_X1qO7p\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am participat la retreaturi, sesiuni profunde de lucru \\u0219i \\u00eent\\u00e2lniri de grup unde oamenii vin s\\u0103 se deschid\\u0103, s\\u0103 se vindece, s\\u0103 se reg\\u0103seasc\\u0103.\"}},{\"id\":\"SBef0jsqm9\",\"type\":\"paragraph\",\"data\":{\"text\":\"De fiecare dat\\u0103, mi-am f\\u0103cut partea mea de lucru cu seriozitate \\u0219i cu smerenie: preg\\u0103tirea spa\\u021biului, aranjarea obiectelor ritualice, construirea cercului, activarea inten\\u021biei, chemarea ghizilor, conectarea cu energiile locului.\"}},{\"id\":\"RHEQcQqn_u\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dar, \\u00een timp, am \\u00eenceput s\\u0103 observ ceva ce nu am putut ignora. Oric\\u00e2t de profund lucram cu inten\\u021bia, oric\\u00e2t de bine ancorat era grupul, exista uneori un sentiment c\\u0103 spa\\u021biul energetic se aglomera sau c\\u0103 anumite emo\\u021bii foarte vechi, grele, poate nici m\\u0103car personale, r\\u0103m\\u00e2neau suspendate \\u00een c\\u00e2mp, f\\u0103r\\u0103 s\\u0103 se dizolve complet.\"}},{\"id\":\"R5T4CqDb9_\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am sim\\u021bit c\\u0103 este nevoie de ceva mai mult. Ceva care s\\u0103 nu fie vizibil, dar s\\u0103 lucreze \\u00een ad\\u00e2ncime. Ceva care s\\u0103 sus\\u021bin\\u0103 spa\\u021biul din interior, dincolo de cuv\\u00e2nt \\u0219i rug\\u0103ciune. A\\u0219a s-a n\\u0103scut ideea unui orgon mare de medita\\u021bii. Nu ca un obiect decorativ, ci ca un instrument viu, cu propria lui con\\u0219tiin\\u021b\\u0103 \\u0219i rol.\"}},{\"id\":\"bNCRsIs44O\",\"type\":\"paragraph\",\"data\":{\"text\":\"<b>Orgonul mare \\u2013 Inima Sanctuarului:<\\/b>\"}},{\"id\":\"xb2d_4RY2_\",\"type\":\"paragraph\",\"data\":{\"text\":\"Construc\\u021bia lui a fost, pentru mine, un ritual \\u00een sine. Nu m-am gr\\u0103bit. Am ales cu aten\\u021bie fiecare component\\u0103: metale, r\\u0103\\u0219in\\u0103, cristale, spirale de cupru, \\u0219i, mai ales, am lucrat mult cu pietrele negre, cele care \\u0219tiu s\\u0103 absoarb\\u0103, s\\u0103 purifice \\u0219i s\\u0103 protejeze: shungit, turmalin\\u0103 neagr\\u0103, obsidian, hematit, dar si cu jasp ro\\u0219u, cuar\\u021b trandafiriu, turmalin\\u0103 mov, agata, cuar\\u021b transparent, etc.\"}},{\"id\":\"KqaoBj27cr\",\"type\":\"paragraph\",\"data\":{\"text\":\"Orgonul mare are o prezen\\u021b\\u0103 aparte. Cei care \\u00eel v\\u0103d pentru prima dat\\u0103 simt imediat c\\u0103 nu este doar un obiect. Are o greutate simbolic\\u0103 \\u0219i energetic\\u0103. Este ca un &nbsp;\\u201est\\u00e2lp \\u00eentre lumi\\u201d, un centru de echilibru, un izvor de purificare.\"}},{\"id\":\"FjExFLzD4_\",\"type\":\"paragraph\",\"data\":{\"text\":\"De c\\u00e2te ori \\u00eel aducem \\u00een spa\\u021biul de lucru fie \\u00een sesiuni individuale, fie \\u00een retreaturi, \\u00eel a\\u0219ez\\u0103m cu respect. Cei care simt, pot sta sub el \\u00een timpul medita\\u021biilor sau al proceselor mai intense. Am v\\u0103zut oameni care au \\u00eenceput s\\u0103 pl\\u00e2ng\\u0103 imediat ce s-au a\\u0219ezat acolo, f\\u0103r\\u0103 s\\u0103 \\u00een\\u021beleag\\u0103 de ce. Al\\u021bii au spus c\\u0103 s-au sim\\u021bit \\u201esus\\u021binu\\u021bi\\u201d de o prezen\\u021b\\u0103 invizibil\\u0103. Unii au descris o claritate brusc\\u0103, al\\u021bii o lini\\u0219te profund\\u0103.\"}},{\"id\":\"QyKg9pMiRa\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru mine, acest orgon este ca o inim\\u0103 care pulseaz\\u0103 \\u00een mijlocul grupului.\"}},{\"id\":\"oUQP8AnZoo\",\"type\":\"paragraph\",\"data\":{\"text\":\"El nu \\u00eenlocuie\\u0219te nimic din ceea ce facem deja: nu \\u00eenlocuie\\u0219te inten\\u021bia, rug\\u0103ciunea sau con\\u0219tiin\\u021ba. Dar le completeaz\\u0103. Le sus\\u021bine. Le \\u00eenr\\u0103d\\u0103cineaz\\u0103.\"}},{\"id\":\"iiItq31KiS\",\"type\":\"paragraph\",\"data\":{\"text\":\"Este felul meu de a \\u021bine spa\\u021biul, cu unelte create de m\\u00e2inile mele, dar conectate la ceva mult mai mare dec\\u00e2t mine.\"}},{\"id\":\"QaobAbYksI\",\"type\":\"paragraph\",\"data\":{\"text\":\"<b>Cele patru surori Cardinale \\u2013 sprijinul t\\u0103cut din cele patru z\\u0103ri:<\\/b>\"}},{\"id\":\"kZSwlgPfq_\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dup\\u0103 ce am sim\\u021bit efectul profund al orgonului mare, am \\u0219tiut c\\u0103 nu va fi singur. Ca orice centru viu, avea nevoie de o re\\u021bea, de o echip\\u0103, de ancore plasate \\u00een cele patru direc\\u021bii sacre.\"}},{\"id\":\"07TIG-Sm_R\",\"type\":\"paragraph\",\"data\":{\"text\":\"A\\u0219a s-au n\\u0103scut cele patru surori: patru orgoni crea\\u021bi cu aceea\\u0219i grij\\u0103, din acelea\\u0219i materiale puternice, fiecare cu un cristal vizibil \\u00een v\\u00e2rf \\u0219i un amestec dens de metale \\u0219i pietre negre: shungit, turmalin\\u0103, obsidian, hematit, jasp ro\\u0219u.\"}},{\"id\":\"8Gz_7nh4Vi\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fiecare dintre ele e diferit\\u0103 \\u0219i totu\\u0219i fac parte din acela\\u0219i \\u00eentreg. C\\u00e2nd le a\\u0219ez\\u0103m \\u00een punctele cardinale \\u2013 Est, Sud, Vest \\u0219i Nord \\u2013 ceva se \\u00eenchide, dar in acela\\u0219i timp se deschide conexiunea, capacitatea noastr\\u0103 de a iubi si ne conduc mai aproape de punctul 0. Se activeaz\\u0103 o re\\u021bea plin\\u0103 de iubire. Este ca \\u0219i cum spa\\u021biul \\u00eencepe s\\u0103 respire altfel. Mai ad\\u00e2nc. Mai sigur.\"}},{\"id\":\"I9as7yADwk\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am adus aceast\\u0103 structur\\u0103 ultima dat\\u0103 \\u00eentr-un retreat transformational. \\u0218tiam c\\u0103 va fi un proces intens, cu multe deschideri emo\\u021bionale \\u0219i amintiri grele scoase la suprafa\\u021b\\u0103.&nbsp; Acolo am sim\\u021bit, mai mult ca oric\\u00e2nd, c\\u00e2t de important este ca spa\\u021biul s\\u0103 fie \\u021binut nu doar cu inima, ci \\u0219i cu energie direc\\u021bionat\\u0103, cu unelte care lucreaz\\u0103 dincolo de ce putem vedea cu ochii liberi. Au fost momente intense, lacrimi, eliber\\u0103ri profunde. \\u0218i, tot timpul, \\u0219tiam c\\u0103 suntem protejati. C\\u0103 suntem \\u00een siguran\\u021b\\u0103. C\\u0103 ne putem deschide f\\u0103r\\u0103 fric\\u0103.\"}},{\"id\":\"arACcj_0b4\",\"type\":\"paragraph\",\"data\":{\"text\":\"Fie ca vorbim despre terapiile unu la unu, fie despre cercurile de grup, Cercul celor Cinci este prezent al\\u0103turi de noi.\"}},{\"id\":\"lBrmo6JO6i\",\"type\":\"paragraph\",\"data\":{\"text\":\"Iar dac\\u0103 ai ajuns p\\u00e2n\\u0103 aici cu inima deschis\\u0103, \\u00ee\\u021bi las o invita\\u021bie:\"}},{\"id\":\"2emON5K9WO\",\"type\":\"paragraph\",\"data\":{\"text\":\"Poate vei sim\\u021bi s\\u0103 vii al\\u0103turi de noi \\u00eentr-o terapie \\u0219i s\\u0103 experimentezi pe pielea ta aceast\\u0103 sus\\u021binere.\"}},{\"id\":\"7xzfKfCxtC\",\"type\":\"paragraph\",\"data\":{\"text\":\"Sau poate e\\u0219ti terapeut, facilitator, ghid. \\u0218i sim\\u021bi, la r\\u00e2ndul t\\u0103u, nevoia unei echipe t\\u0103cute care s\\u0103 te sus\\u021bin\\u0103 \\u0219i pe tine, \\u00een timp ce tu \\u00eei sus\\u021bii pe ceilal\\u021bi.\"}},{\"id\":\"vVTGKZvHxD\",\"type\":\"paragraph\",\"data\":{\"text\":\"Caut\\u0103-\\u021bi alia\\u021bii. Pot fi cristale, obiecte sacre, rug\\u0103ciuni, str\\u0103mo\\u0219i, spirale de cupru sau p\\u0103m\\u00e2ntul pe care calci.\"}},{\"id\":\"g71Hc7TWKP\",\"type\":\"paragraph\",\"data\":{\"text\":\"Important e s\\u0103 \\u0219tii c\\u0103 nu e\\u0219ti singur.\"}},{\"id\":\"RXDo4OL_iw\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru mine, aceast\\u0103 echip\\u0103 e format\\u0103 din orgonul mare \\u0219i cele patru surori.\"}},{\"id\":\"vonGv4B1yv\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00cempreun\\u0103, \\u021binem spa\\u021biul acolo unde cuvintele se opresc\\u2026 \\u0219i \\u00eencepe vindecarea.\"}}],\"version\":\"2.31.0-rc.7\"}', 6, 'Asociatia Lotus Retreat', '2025-07-01 14:48:23', '2025-07-03 12:36:33');
INSERT INTO `posts` (`id`, `title`, `slug`, `excerpt`, `preview_image`, `description`, `order`, `created_by`, `created_at`, `updated_at`) VALUES
(16, 'Când un retreat devine o inițiere - Despre Fire & Ice', 'cand-un-retreat-devine-o-initiere-despre-fire-ice-6865171139732', '<p>Există retreaturi în care vii să te relaxezi. Și există retreaturi care îți răstoarnă lumea cu susul în jos…</p>', 'posts/preview_images/lbYYfOUC7i2gy6LDAAB5VzrP1vFG4bCw9QUGfThE.jpg', '{\"time\":1751554148399,\"blocks\":[{\"id\":\"JNZtOybuPj\",\"type\":\"paragraph\",\"data\":{\"text\":\"Exist\\u0103 retreaturi \\u00een care vii s\\u0103 te relaxezi si exist\\u0103 retreaturi care \\u00ee\\u021bi r\\u0103stoarn\\u0103 lumea cu susul \\u00een jos\\u2026 ca s\\u0103 o rea\\u0219eze, \\u00een sf\\u00e2r\\u0219it, cu fa\\u021ba spre suflet. Nu am \\u0219tiut ce urma s\\u0103 tr\\u0103im \\u00een acele 6 zile. Nu am avut a\\u0219tept\\u0103ri.&nbsp;Tot ce am f\\u0103cut a fost s\\u0103 ne deschidem. S\\u0103 spunem da. S\\u0103 fim vulnerabili, reali \\u0219i prezen\\u021bi \\u2013 \\u00een fa\\u021ba vie\\u021bii, \\u00een fa\\u021ba celuilalt, \\u00een fa\\u021ba grupului. \\u0218i atunci\\u2026 via\\u021ba a \\u00eenceput s\\u0103 ne vorbeasc\\u0103. Prin medita\\u021bii care au scos la lumin\\u0103 r\\u0103ni vechi. Prin \\u00eentunericul care ne-a \\u00eenv\\u0103\\u021bat s\\u0103 vedem. Prin salturi \\u00een gol care ne-au \\u00eenv\\u0103\\u021bat despre \\u00eencredere. Prin \'\'accidente rutiere\'\' care au adus lec\\u021bii. Prin foc, ghea\\u021b\\u0103, respira\\u021bie \\u0219i lacrimi care au ars tot ce nu ne mai servea.\"}},{\"id\":\"uQ8w1H9amU\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am tr\\u0103it fiecare zi at\\u00e2t prin ochii \\u0219i inima unei femei, c\\u00e2t \\u0219i din tr\\u0103irea profund\\u0103 a unui b\\u0103rbat.\"}},{\"id\":\"1ufLE_A8w8\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dou\\u0103 perspective. Dou\\u0103 ritmuri. Un singur adev\\u0103r: transformarea \\u00eencepe c\\u00e2nd ne l\\u0103s\\u0103m s\\u0103 sim\\u021bim.\"}},{\"id\":\"m9EYBJPmFu\",\"type\":\"paragraph\",\"data\":{\"text\":\"Te invit\\u0103m s\\u0103 cite\\u0219ti mai departe \\u2013 nu ca pe o poveste despre noi, ci ca pe o oglind\\u0103 \\u00een care poate, \\u00eentr-un moment, te vei recunoa\\u0219te \\u0219i tu.&nbsp;\\u00cen primele zile, am ales s\\u0103 \\u00eemp\\u0103rt\\u0103\\u0219im tr\\u0103irile noastre separat \\u2013 atat din perspectiva mea, a Sandrei, dar \\u0219i din perspectiva lui George. Iar pe m\\u0103sur\\u0103 ce zilele s-au a\\u0219ezat in suflet, pove\\u0219tile noastre s-au \\u00eempletit firesc \\u00eentr-una singur\\u0103.\"}},{\"id\":\"xrykalVMU6\",\"type\":\"header\",\"data\":{\"text\":\"Ziua 1 \\u2013 \\u00centre frica de a tr\\u0103i \\u0219i curajul de a fi\",\"level\":2}},{\"id\":\"MGXeT4YwKY\",\"type\":\"paragraph\",\"data\":{\"text\":\"Exist\\u0103 momente care te opresc din rutina zilnic\\u0103, din alergare, te a\\u0219az\\u0103 pe podeaua sufletului \\u0219i te \\u00eentreab\\u0103 simplu, t\\u0103ios \\u0219i clar:\"}},{\"id\":\"VnzE-UnUxi\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\\"Tu vrei s\\u0103 tr\\u0103ie\\u0219ti cu adev\\u0103rat? Sau doar supravie\\u021buie\\u0219ti \\u00een decorul propriei tale vie\\u021bi?\\\"\"}},{\"id\":\"6wAGZ1R51h\",\"type\":\"paragraph\",\"data\":{\"text\":\"A\\u0219a a \\u00eenceput prima zi. Cu o medita\\u021bie profund\\u0103, deschiz\\u0103toare de por\\u021bi interioare, care a adus in prim plan straturi vechi de fric\\u0103 \\u0219i ru\\u0219ine. Printr-o simpl\\u0103 \\u00eentrebare care a scos la lumin\\u0103 tot ce era neasumat, tot ce r\\u0103m\\u0103sese blocat \\u00een copil\\u0103rie, \\u00een mintea care a \\u00eenv\\u0103\\u021bat prea devreme c\\u0103 dac\\u0103 nu este perfect, mai bine te opre\\u0219ti. C\\u0103 dac\\u0103 nu e\\u0219ti impecabil, lumea te judec\\u0103, te ru\\u0219ineaz\\u0103, te uit\\u0103.\"}},{\"id\":\"sdefjypX-1\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mi-am amintit un moment din clasa \\u00eent\\u00e2i. Eu, \\u00een fa\\u021ba clasei, spun\\u00e2nd o poezie. M-am \\u00eencurcat. \\u0218i pentru c\\u0103 nu era perfect, m-am oprit. Am ales t\\u0103cerea. Am ales s\\u0103 nu mai continui.\"}},{\"id\":\"-o54pCidSE\",\"type\":\"paragraph\",\"data\":{\"text\":\"De atunci, via\\u021ba s-a \\u00eemp\\u0103r\\u021bit \\u00eentre ce pot \\u0219i ce nu am voie. \\u00centre ce este sigur \\u0219i ce ar putea s\\u0103 doar\\u0103.\"}},{\"id\":\"CYDspjVu-j\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00centre frica de a fi v\\u0103zut\\u0103 gre\\u0219ind \\u0219i nevoia profund\\u0103 de a fi iubit\\u0103 chiar \\u0219i atunci c\\u00e2nd nu iese \\u201ebine\\u201d.\"}},{\"id\":\"Yo53ssAn0s\",\"type\":\"paragraph\",\"data\":{\"text\":\"In prima seara din tab\\u0103r\\u0103 am fost chemat\\u0103 s\\u0103-mi privesc direct \\u00een ochi frica de a tr\\u0103i. Nu frica de a muri. Ci frica de a tr\\u0103i cu adev\\u0103rat. Frica de entuziasm, de reu\\u0219it\\u0103, de iubire, de bucurie. Frica aceea subtil\\u0103 care te saboteaz\\u0103 din umbr\\u0103, care-\\u021bi spune: \\u201eMai bine nu. Mai bine nu sim\\u021bi. Mai bine nu visezi.\\u201d\"}},{\"id\":\"zemljOGw7i\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00cen timpul medita\\u021biei, am sim\\u021bit c\\u0103 aceast\\u0103 tab\\u0103r\\u0103 nu este despre a trece prin foc \\u0219i ghea\\u021b\\u0103 ca s\\u0103 dovede\\u0219ti ceva. Este despre a-\\u021bi aminti c\\u00e2t de puternic e\\u0219ti deja. C\\u00e2t\\u0103 credin\\u021b\\u0103 po\\u021bi accesa \\u00een tine. C\\u00e2t din via\\u021ba ta se transform\\u0103 atunci c\\u00e2nd nu mai alegi frica, ci alegi \\u00een mod con\\u0219tient\\u2026 credin\\u021ba.\"}},{\"id\":\"kwdZPE3p2e\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u0218i tot \\u00een aceast\\u0103 zi, am atins o ran\\u0103 profund\\u0103: frica de singur\\u0103tate. In timpul medita\\u021biei mi s-a ar\\u0103tat ca este corelat\\u0103 cu frica de a trai. Iar aceasta nu voia sa m\\u0103 lase sa devin autonom\\u0103. C\\u0103ci dac\\u0103 devin cu adev\\u0103rat autonom\\u0103\\u2026 \\u00eenseamn\\u0103 c\\u0103 pot fi singur\\u0103. C\\u0103 nu mai depind. C\\u0103 nu mai cer. C\\u0103 nu mai suf\\u0103r.\"}},{\"id\":\"oH4QSVR_vZ\",\"type\":\"paragraph\",\"data\":{\"text\":\"Frica de singur\\u0103tate este parazitar\\u0103. Se ascunde \\u00een burt\\u0103, \\u00een furie, \\u00een durere, \\u00een reac\\u021bii fa\\u021b\\u0103 de alte persoane care nu sunt despre ei, ci despre mine \\u2013 copilul care s-a sim\\u021bit respins. Copilul care a fost l\\u0103sat singur. Copilul care a \\u00eenv\\u0103\\u021bat c\\u0103 Dumnezeu l-a abandonat.\"}},{\"id\":\"JLSZPQXq2b\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u0218i atunci, am ales sa \\u00eemi dezvolt mecanisme de ap\\u0103rare. C\\u00e2nd eram mica am ales sa mint. Nu doar pe ceilal\\u021bi. Ci si pe mine. Am colorat realitatea, am construit iluzii mai bl\\u00e2nde, am \\u00eembr\\u0103cat rana \\u00een poezie, doar ca s\\u0103 nu doar\\u0103 prea tare. Dar \\u00een acela\\u0219i timp, \\u00eentotdeauna am avut ceva: voin\\u021b\\u0103.\"}},{\"id\":\"EDk-WETK2W\",\"type\":\"paragraph\",\"data\":{\"text\":\"Voin\\u021ba de a schimba. Voin\\u021ba de a nu r\\u0103m\\u00e2ne \\u00een ru\\u0219ine. Voin\\u021ba de a ie\\u0219i din umilin\\u021b\\u0103, chiar dac\\u0103 uneori mi-a fost team\\u0103. Chiar dac\\u0103 am crezut c\\u0103 nu merit. \\u0218i din acea zi, ceva s-a schimbat. Un g\\u00e2nd s-a a\\u0219ezat \\u00een mine cu o claritate care nu cere dovezi: Dumnezeu este cu mine. \\u00centre dou\\u0103 g\\u00e2nduri. \\u00centre dou\\u0103 respira\\u021bii.\"}},{\"id\":\"crbd8vNvBd\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am ales sa nu mai fug. Sa nu mai neg. Sa nu mai port ru\\u0219inea ca pe o a doua piele. Din acel moment am ales s\\u0103-mi onorez darul. \\u0218i s\\u0103 fac tot ce \\u021bine de mine ca s\\u0103 atrag oamenii care au nevoie de munca mea. S\\u0103 nu m\\u0103 mai ascund. S\\u0103 nu mai a\\u0219tept validare. S\\u0103 m\\u0103 ofer. Cu tot ce sunt.\"}},{\"id\":\"wNnBFsZs4Q\",\"type\":\"paragraph\",\"data\":{\"text\":\"Aceast\\u0103 c\\u0103l\\u0103torie a \\u00eenceput sub o sus\\u021binere rar\\u0103, sf\\u00e2nt\\u0103 chiar. Medita\\u021bia a fost ghidat\\u0103 de R\\u0103zvan Dinc\\u0103 \\u2013 un suflet cum rar \\u00ee\\u021bi este dat s\\u0103 \\u00eent\\u00e2lne\\u0219ti. At\\u00e2t de mult\\u0103 iubire, bl\\u00e2nde\\u021be \\u0219i prezen\\u021b\\u0103 pur\\u0103 \\u00eentr-un singur om, nu mai sim\\u021bisem p\\u00e2n\\u0103 atunci. A sus\\u021binut spa\\u021biul nu doar fizic, ci \\u0219i energetic, \\u00eentr-un mod care a permis fiec\\u0103ruia s\\u0103 se simt\\u0103 v\\u0103zut, con\\u021binut, iubit exact a\\u0219a cum este. A fost un sprijin profund. O ancor\\u0103 \\u00een acele zile \\u00een care mul\\u021bi dintre noi ne-am \\u00eentors la r\\u0103d\\u0103cina fricii \\u0219i am ales, poate pentru prima dat\\u0103: s\\u0103 tr\\u0103im cu adev\\u0103rat.\"}},{\"id\":\"tOSlCR6AmW\",\"type\":\"paragraph\",\"data\":{\"text\":\"<b><i>Mi-am \\u00eentrebat si so\\u021bul, George, cum a fost prima zi pentru el ?<\\/i><\\/b>\"}},{\"id\":\"58-Eaj29lg\",\"type\":\"paragraph\",\"data\":{\"text\":\"<b>-Conexiune, viziune \\u0219i canal de lumin\\u0103-<\\/b>\"}},{\"id\":\"GEZj1ZLOEE\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Pentru mine, \\u00eenceputul acestui retreat a fost mai mult dec\\u00e2t deschiderea unui spa\\u021biu fizic. A fost deschiderea unui canal de lumin\\u0103. \\u00cen timp ce preg\\u0103team locul, sim\\u021beam cum energia \\u00eencepe s\\u0103 curg\\u0103 c\\u0103tre&nbsp;noi, printre inimi si inten\\u021bii.<\\/i> <i>Fiecare participant a venit cu o c\\u0103utare, dar mai ales cu o lumin\\u0103 proprie. Am sim\\u021bit asta din prima clip\\u0103<\\/i>.\"}},{\"id\":\"mu8492iXqd\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>\\u00cen timpul medita\\u021biei, am avut o viziune foarte clar\\u0103: unul dintre participan\\u021bi devenea un canal de coduri de lumin\\u0103, desc\\u0103rc\\u00e2nd \\u00een plan subtil informa\\u021bie pur\\u0103. Dar ceea ce m-a impresionat cu adev\\u0103rat a fost c\\u0103 fiecare om din cerc era conectat la surs\\u0103. Era ca \\u0219i cum de la fiecare pornea un fir de lumin\\u0103 \\u00een sus, form\\u00e2nd o re\\u021bea. Un c\\u00e2mp. O prezen\\u021b\\u0103.<\\/i>\"}},{\"id\":\"d8EkX8Q4Jq\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Spa\\u021biul s-a deschis repede. A fost sinceritate. Autenticitate. Lacrimi. Recunoa\\u0219tere. Iar noi am ales doar sa fim. \\u0218i asta, pentru mine, a fost \\u00eenceputul a ceva mai mare dec\\u00e2t un retreat: a fost \\u00eenceputul unei familii energetice.<\\/i>\"}},{\"id\":\"lOQo2TI-Uk\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>A\\u0219a a fost prima zi. Cu frici scoase la lumin\\u0103. Cu decizii t\\u0103cute, dar ferme. Cu inimi deschise. Cu divinitatea prezenta. \\u0218i cu hot\\u0103r\\u00e2rea clar\\u0103 de a merge p\\u00e2n\\u0103 la cap\\u0103t.<\\/i>\"}},{\"id\":\"rUZjBfdevH\",\"type\":\"header\",\"data\":{\"text\":\"Ziua 2 \\u2013 C\\u00e2nd am p\\u0103\\u0219it \\u00een \\u00eentuneric, umbrele noastre au devenit vizibile\",\"level\":2}},{\"id\":\"2ju4TQvRuj\",\"type\":\"paragraph\",\"data\":{\"text\":\"<b>George \\u2013 <i>Muzica vindec\\u0103. Ne-a unit sufletele.<\\/i><\\/b>\"}},{\"id\":\"pwDgAG195L\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Miercuri dup\\u0103 amiaza a fost un moment rar, din acelea pe care sufletul le recunoa\\u0219te ca vindec\\u0103toare \\u00eenainte ca mintea s\\u0103 \\u00een\\u021beleag\\u0103 de ce: R\\u0103zvan a c\\u00e2ntat. La pian. Cu vocea. Cu toat\\u0103 fiin\\u021ba lui. Nu a fost doar un simplu artist, ci un conector intre vibra\\u021biile iubirii si a inimilor tuturor celor prezen\\u021bi.<\\/i>&nbsp;\"}},{\"id\":\"mMGCtjI4YX\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Nu ca artist. Ci ca vehicul al unei iubiri care curge din alte lumi. Spre final am c\\u00e2ntat si \\u00eempreun\\u0103.&nbsp;Ca \\u0219i cum muzica ne adunase la unison.&nbsp;Fiecare voce era un fir de aur care ie\\u0219ea din inim\\u0103. &nbsp;Fiecare ton ne lega unii de al\\u021bii. \\u0218i f\\u0103r\\u0103 s\\u0103 \\u0219tim, ne vindecam. Nu prin explica\\u021bii. Ci prin prezen\\u021b\\u0103. Ritm. Vibra\\u021bie.<\\/i>\"}},{\"id\":\"4kzL-f8PKU\",\"type\":\"paragraph\",\"data\":{\"text\":\"<b>Sandra<\\/b>\"}},{\"id\":\"7hg1QmasMC\",\"type\":\"paragraph\",\"data\":{\"text\":\"Exista locuri \\u00een care t\\u0103cerea nu \\u00eenseamn\\u0103 lipsa sunetului, ci prezen\\u021b\\u0103 \\u00een cea mai pur\\u0103 form\\u0103. \\u0218i exist\\u0103 momente \\u00een care \\u00eentunericul nu este lipsit de lumin\\u0103, ci este o alt\\u0103 form\\u0103 a ei \\u2013 una care nu te orbe\\u0219te, ci te aduce \\u00eenapoi \\u00een tine.\"}},{\"id\":\"P7KhzKqKWO\",\"type\":\"paragraph\",\"data\":{\"text\":\"A\\u0219a a fost noaptea \\u00een chilie. Am intrat singur\\u0103 acolo, ghidat\\u0103 de R\\u0103zvan, \\u0219i am r\\u0103mas cu mine timp de zece minute, \\u00een lini\\u0219te \\u0219i in \\u00eentuneric total. A fost o retragere scurt\\u0103, dar ad\\u00e2nc\\u0103. Un spa\\u021biu \\u00een care g\\u00e2ndurile nu mai aveau unde s\\u0103 se aga\\u021be, \\u00een care sim\\u021burile se dilatau \\u0219i prezen\\u021ba devenea singura realitate.\"}},{\"id\":\"5PFZLq9WwC\",\"type\":\"paragraph\",\"data\":{\"text\":\"Nu mi-am pus \\u00eentreb\\u0103ri, nu am for\\u021bat nimic. M-am rugat. Sau mai bine spus\\u2026 m-am a\\u0219ezat \\u00een acel loc unde rug\\u0103ciunea se na\\u0219te singur\\u0103 din respira\\u021bie.\"}},{\"id\":\"fJsCPxFYuV\",\"type\":\"paragraph\",\"data\":{\"text\":\"C\\u00e2nd am ie\\u0219it, R\\u0103zvan m-a \\u00eentrebat cu bl\\u00e2nde\\u021be: \\u201eCe sim\\u021bi?\\u201d\"}},{\"id\":\"8DncePudk2\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u0218i am r\\u0103spuns sincer: \\u201eNu \\u0219tiu ce simt.\\u201d\"}},{\"id\":\"qsRZkFLBHx\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru c\\u0103 nu era o emo\\u021bie anume, ci o t\\u0103cere profund\\u0103 care \\u00eemi umplea tot trupul. O pace care nu venea dintr-un \\u201ea \\u00een\\u021beles\\u201d ceva, ci din faptul c\\u0103 nimic nu mai trebuia \\u00een\\u021beles. M-am retras pu\\u021bin din grup. Sim\\u021beam nevoia s\\u0103 stau cu mine, nu pentru c\\u0103 fugeam de ceilal\\u021bi, ci pentru c\\u0103 \\u00eentunericul \\u00eenc\\u0103 \\u00eemi pulsa \\u00een oase ca o binecuv\\u00e2ntare. \\u0218i abia atunci, \\u00een acea lini\\u0219te interioar\\u0103, am avut revela\\u021bia simpl\\u0103: noaptea \\u0219i \\u00eentunericul sunt f\\u0103cute pentru lini\\u0219te, pentru pace \\u2013 dar doar dac\\u0103 nu \\u00ee\\u021bi mai este team\\u0103 de ele. Pentru c\\u0103 frica le face s\\u0103 devin\\u0103 du\\u0219mani. Dar c\\u00e2nd le \\u00eent\\u00e2mpini cu \\u00eencredere, devin o poart\\u0103. Un p\\u00e2ntec. O \\u00eentoarcere.\"}},{\"id\":\"9YpDhmAI2w\",\"type\":\"header\",\"data\":{\"text\":\"Ziua 3 \\u2013 C\\u0103dere \\u00een gol, \\u00eencredere \\u00een zbor\",\"level\":2}},{\"id\":\"pkmiey2xU_\",\"type\":\"paragraph\",\"data\":{\"text\":\"Diminea\\u021ba de joi ne-a \\u00eent\\u00e2mpinat cu un cer senin \\u0219i o promisiune nerostit\\u0103: ast\\u0103zi urma s\\u0103 \\u00eenv\\u0103\\u021b\\u0103m ce \\u00eenseamn\\u0103 s\\u0103 te abandonezi total vie\\u021bii. S\\u0103 sari, la propriu, \\u00een necunoscut. S\\u0103-\\u021bi \\u00eenfrun\\u021bi fricile nu doar simbolic, ci cu fiecare fibr\\u0103 a corpului.\"}},{\"id\":\"PRxhNA4cGz\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00cenainte de a ne urca \\u00een avion, R\\u0103zvan a sus\\u021binut o scurt\\u0103 medita\\u021bie. Calm, prezent, profund conectat la fiecare dintre noi. A fost momentul \\u00een care ne-am reamintit inten\\u021bia. Nu venisem aici pentru adrenalin\\u0103. Venisem s\\u0103 ne dep\\u0103\\u0219im limitele interioare. S\\u0103 ie\\u0219im din vechile tipare. S\\u0103 s\\u0103rim din fric\\u0103 \\u00een credin\\u021b\\u0103.\"}},{\"id\":\"d17gkjb4kA\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":true,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/O6UhmyfyX3PaJEq87hNAMOqCP9JLgRJPMYR8EkQU.jpg\"}}},{\"id\":\"Tz_5qSxOXI\",\"type\":\"paragraph\",\"data\":{\"text\":\"<b>Cum am tr\\u0103it&nbsp;eu, Sandra, aceasta zi:<\\/b>\"}},{\"id\":\"-Z4MHZvjne\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am urcat \\u00een avion cu inima deschis\\u0103. F\\u0103r\\u0103 fric\\u0103. Doar entuziasm. Dar c\\u00e2nd am v\\u0103zut c\\u0103 u\\u0219a avionului nu se \\u00eenchide complet\\u2026 iar hamurile nu erau str\\u00e2nse complet, am sim\\u021bit un gol \\u00een stomac.Un \\\"nu mai pot da \\u00eenapoi\\\". Un \\u201enu mai pot controla nimic\\u201d. Respira\\u021bia mi s-a blocat. Totul era prea rapid, prea real, prea \\u00een afara zonei mele de confort. \\u0218i apoi\\u2026 saltul. C\\u0103derea liber\\u0103, care pentru mine a fost o moarte simbolic\\u0103.\"}},{\"id\":\"wuEUEWOMQ9\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am fost pus\\u0103 fa\\u021b\\u0103 \\u00een fa\\u021b\\u0103 cu propria fric\\u0103 de moarte \\u0219i cu lipsa de control. \\u0218i \\u00een acela\\u0219i timp, cu o via\\u021b\\u0103 pe care o sim\\u021beam doar pe jum\\u0103tate tr\\u0103it\\u0103. A fost momentul \\u00een care corpul meu a \\u00een\\u021beles c\\u0103 poate tr\\u0103i f\\u0103r\\u0103 fric\\u0103. C\\u0103 poate s\\u0103 se lase purtat.\"}},{\"id\":\"wU60itO0j4\",\"type\":\"paragraph\",\"data\":{\"text\":\"C\\u00e2nd s-a deschis para\\u0219uta, totul s-a schimbat. Viteza a devenit plutire. Frica s-a transformat \\u00een bucurie pur\\u0103. M\\u0103 sim\\u021beam ca \\u0219i cum Dumnezeu m-ar fi prins \\u00een bra\\u021be. Zburam si eram plin\\u0103 de recuno\\u0219tin\\u021b\\u0103. Nu-mi sim\\u021beam picioarele de emo\\u021bie \\u0219i de libertate. Nu cred c\\u0103 am mai tr\\u0103it vreodat\\u0103 o recuno\\u0219tin\\u021b\\u0103 at\\u00e2t de autentic\\u0103.\"}},{\"id\":\"wqvAKxzQOB\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mi-am dat seama acolo c\\u00e2t de intens ne protejeaz\\u0103 m\\u0103\\u0219tile. Cum mintea construie\\u0219te o realitate \\u00eentreag\\u0103 doar ca s\\u0103 nu sim\\u021bim durerea abandonului, a singur\\u0103t\\u0103\\u021bii, a incertitudinii. Dar \\u00een fa\\u021ba cerului, m\\u0103\\u0219tile cad.\"}},{\"id\":\"OkAd33zZOP\",\"type\":\"paragraph\",\"data\":{\"text\":\"<b><i>Mi-am \\u00eentrebat si so\\u021bul, George, cum a fost aceasta zi pentru el:<\\/i><\\/b><br>\"}},{\"id\":\"VcwNaDPR4q\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Pentru mine, ziua asta a \\u00eenceput cu fric\\u0103. Frica real\\u0103. Frica de moarte. N-am s\\u0103rit niciodat\\u0103 cu para\\u0219uta. \\u0218i n-a\\u0219 fi f\\u0103cut-o dac\\u0103 n-ar fi fost despre ceva mai mare dec\\u00e2t mine.<\\/i>\"}},{\"id\":\"gz3Onli_oP\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Tot drumul p\\u00e2n\\u0103 acolo am vorbit cu un alt b\\u0103rbat din grup. Despre ce \\u00eenseamn\\u0103, in zilele noastre, un b\\u0103rbat autentic. Un b\\u0103rbat care vine la retreaturi, care alege s\\u0103 se vindece, s\\u0103 se dezv\\u0103luie. Am vorbit despre vulnerabilitate, despre puterea inimii, despre faptul c\\u0103 nu mai avem nimic de dovedit, ci doar de deschis \\u00een noi.<\\/i>\"}},{\"id\":\"O4YRBGlz2R\",\"type\":\"paragraph\",\"data\":{\"text\":\"A<i>h, \\u0219i instructorul meu cu care am s\\u0103rit glumea constant c\\u0103 e pensionar, c\\u0103 nu are experien\\u021b\\u0103, ca \\u00ee\\u0219i tr\\u0103ie\\u0219te visul de a zbura pentru primele sale da\\u021bi si ca se roag\\u0103 sa se deschid\\u0103 para\\u0219uta. Am r\\u00e2s. Un r\\u00e2s mai mult tremurat. Dar &nbsp;dincolo de orice glum\\u0103, sim\\u021beam protec\\u021bia divin\\u0103.<\\/i>\"}},{\"id\":\"TPE7xW2Mox\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Am urcat \\u00een avion al\\u0103turi de so\\u021bia mea \\u0219i de o prietena, ca o sora in aceasta via\\u021ba. A fost ca o hor\\u0103 de suflet. Ne-am privit. \\u0218i am sim\\u021bit cum ne-am promis c\\u0103 ne vedem jos. A fost un salt \\u00een credin\\u021b\\u0103. S-a deschis u\\u0219a avionului \\u0219i \\u00een mine era doar rug\\u0103ciune.<\\/i>&nbsp;\"}},{\"id\":\"k6JHeempCD\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>\\u00cen acea c\\u0103dere de la 4000 de metri, ceva \\u00een mine s-a resetat. A fost o ini\\u021biere. C\\u00e2nd <\\/i>am atins p\\u0103m\\u00e2ntul, nu mai eram acela\\u0219i. Era un George mai con\\u0219tient, mai vulnerabil, mai viu.\"}},{\"id\":\"ZTw1mNoxUY\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Ce mi-a r\\u0103mas \\u00een suflet a fost ideea c\\u0103 oricine poate s\\u0103 sar\\u0103 cu para\\u0219uta pentru adrenalin\\u0103. Dar s\\u0103 o faci cu inten\\u021bia de a te transforma, de a alchimiza din tine frici, de a merge c\\u0103tre o rela\\u021bie mai curat\\u0103, c\\u0103tre un business al sufletului t\\u0103u\\u2026 asta e cu totul altceva.<\\/i>\"}},{\"id\":\"UmXzprgeUk\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Seara ne-a g\\u0103sit aduna\\u021bi \\u00een cerc in jurul focului. Trecuser\\u0103m prin nori, prin aer, prin propriile frici \\u2013 iar acum era timpul s\\u0103 cobor\\u00e2m din nou in interiorul nostru. Sandra a deschis spa\\u021biul unei medita\\u021bii profunde, ghid\\u00e2ndu-ne pas cu pas \\u00een labirintul celor cinci r\\u0103ni interioare. Iar eu, George, am sus\\u021binut spa\\u021biul cu o prezen\\u021b\\u0103 profund masculin\\u0103, ancorat\\u0103 \\u0219i bl\\u00e2nd\\u0103.&nbsp;Nu a fost o simpl\\u0103 explorare emo\\u021bional\\u0103. Nu a fost o c\\u0103l\\u0103torie imaginar\\u0103. A fost real. S-a pl\\u00e2ns, s-a urlat, s-a r\\u00e2s. Ne-am conectat cu vulnerabilitatea si s-au eliberat voci \\u00eenn\\u0103bu\\u0219ite de ani la r\\u00e2nd.<\\/i>\"}},{\"id\":\"Bt8DBD13ak\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Ne-am ad\\u00e2ncit \\u00een cele mai grele momente ale noastre, am stat acolo, fiecare \\u00een fa\\u021ba propriei r\\u0103ni, a propriului gol, a propriului adev\\u0103r nerostit. \\u0218i din acel loc al \\u00eentunericului dens, ceva a \\u00eenceput s\\u0103 se aprind\\u0103. A fost o rena\\u0219tere.<\\/i>\"}},{\"id\":\"moXpltJ2X8\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>Unii au aflat \\u00een acea sear\\u0103 lucruri despre ei \\u00een\\u0219i\\u0219i, pe care nu le b\\u0103nuiser\\u0103 niciodat\\u0103. Adev\\u0103ruri care au fost acolo dintotdeauna, dar care nu avuseser\\u0103 p\\u00e2n\\u0103 atunci curajul s\\u0103 ias\\u0103 la suprafa\\u021b\\u0103. A fost o sear\\u0103 de purificare. De confruntare. De reamintire. A fost o sear\\u0103 \\u00een care grupul s-a legat \\u00eentr-un mod irevocabil, prin vulnerabilitate, prin curajul de a sim\\u021bi totul \\u0219i de a nu fugi de nimic. <\\/i>\"}},{\"id\":\"L2qERKco-n\",\"type\":\"paragraph\",\"data\":{\"text\":\"<i>A fost ziua \\u00een care nu doar am zburat. A fost ziua \\u00een care ne-am \\u00eentors \\u00een via\\u021b\\u0103, cu sufletele pu\\u021bin mai goale de fric\\u0103 \\u0219i pu\\u021bin mai pline de adev\\u0103r.<\\/i>\"}},{\"id\":\"muHylsvgVO\",\"type\":\"header\",\"data\":{\"text\":\"Ziua 4 \\u2013 Fricile mo\\u0219tenite \\u0219i urcarea c\\u0103tre claritate\",\"level\":2}},{\"id\":\"wQbhXjWYi-\",\"type\":\"paragraph\",\"data\":{\"text\":\"Diminea\\u021ba ne-a \\u00eent\\u00e2mpinat cu o alt\\u0103 ini\\u021biere: urcarea pe munte. Dar p\\u00e2n\\u0103 s\\u0103 ajungem la v\\u00e2rf, am fost chema\\u021bi s\\u0103 cobor\\u00e2m mai \\u00eent\\u00e2i \\u00een propriile umbre. Pentru mine, Sandra, ziua a \\u00eenceput sim\\u021bind o bucurie aparte ca aveam oportunitatea sa conduc ma\\u0219ina. Am luat volanul \\u00een m\\u00e2ini cu bucurie, cu \\u00eencredere. Dar \\u0219i cu o tensiune subtil\\u0103 \\u00een aer. George, al\\u0103turi de mine, \\u00eemi spunea constant: \\u201eE\\u0219ti prea aproape de margine.\\u201d \\u201eAi intrat prea mult \\u00een st\\u00e2nga.\\u201d \\u201eAi grij\\u0103.\\u201d\"}},{\"id\":\"H0JHV-7ALf\",\"type\":\"paragraph\",\"data\":{\"text\":\"La \\u00eenceput l-am ascultat. Apoi m-am sim\\u021bit din ce \\u00een ce mai mic\\u0103. \\u0218i exact atunci, o ma\\u0219in\\u0103 din fa\\u021ba mea, cu acela\\u0219i num\\u0103r de jude\\u021b ca al nostru \\u2013 un fel de dublu \\u00een oglind\\u0103 \\u2013 a virat brusc dreapta. Iar eu\\u2026 am \\u00eencremenit. Efectiv nu am putut apas\\u0103 pe fr\\u00e2na. Mergeam destul de incet, motiv pentru care a fost un accident minor, insa cu un ecou profund.&nbsp;\"}},{\"id\":\"P06u8u3h5g\",\"type\":\"paragraph\",\"data\":{\"text\":\"Am \\u00een\\u021beles mai t\\u00e2rziu c\\u0103 acel accident simboliza frica \\u2013 sau cum ne place noua sa ii spunem, am chemat ursul. Dar aici, \\u201eursul\\u201d nu era \\u00een p\\u0103dure. Era frica lui George, transformat\\u0103 \\u00een reac\\u021bie. \\u00cen protec\\u021bie excesiv\\u0103. \\u00cen replica tat\\u0103lui care i-a fost c\\u00e2ndva critic \\u0219i exigent. F\\u0103r\\u0103 s\\u0103-\\u0219i dea seama, George a devenit pentru mine exact ceea ce-l r\\u0103nise pe el c\\u00e2nd a \\u00eenv\\u0103\\u021bat s\\u0103 conduc\\u0103. Vocea tat\\u0103lui s\\u0103u a r\\u0103sunat prin gura lui.\"}},{\"id\":\"CeFnwoJSyr\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru mine, a fost o \\u00eent\\u00e2lnire direct\\u0103 cu rana de umilin\\u021b\\u0103. Tonul lui, reac\\u021bia, furia &nbsp;\\u2013 toate m-au dus \\u00eentr-un spa\\u021biu interior \\u00een care nu mai aveam voie s\\u0103 gre\\u0219esc. \\u0218i nici s\\u0103 simt. Eu nu vedeam nicio problem\\u0103. Dar corpul meu se str\\u00e2ngea. Inima mea se \\u00eenchidea.\"}},{\"id\":\"54J6cN-Frp\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":true,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/YnVeWtPt6wYB2xsnv0yytHfgeDGomuLdWrWim1K9.jpg\"}}},{\"id\":\"hGK26o13eL\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dup\\u0103 o conversa\\u021bie profund\\u0103 cu R\\u0103zvan, George a \\u00eenceput s\\u0103 con\\u0219tientizeze mecanismul. A v\\u0103zut clar care rana a atras experien\\u021ba care l-a reactivat \\u2013 nu ca s\\u0103 ne pedepseasc\\u0103, ci ca s\\u0103 ne invite la vindecare. \\u0218i ce a fost frumos\\u2026 e c\\u0103 a integrat rapid. L-am sim\\u021bit deschiz\\u00e2ndu-se. Schimb\\u00e2ndu-se. Cer\\u00e2ndu-\\u0219i iertare. Nu din vinov\\u0103\\u021bie, ci din iubire.\"}},{\"id\":\"4cryZ9vHjl\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pe durata traseului pana la V\\u00e2rful Ciuca\\u0219, George l-a purtat pe Ianis \\u00een spate. Mersul devenise spa\\u021biu de introspec\\u021bie. Am vorbit tot urcu\\u0219ul: despre reac\\u021biile noastre, despre r\\u0103nile din spatele lor, despre cum ne-am oglindit unul altuia fricile, nevoile, dorin\\u021bele nerostite.\"}},{\"id\":\"exPDbftuMG\",\"type\":\"paragraph\",\"data\":{\"text\":\"C\\u00e2nd am ajuns \\u00een v\\u00e2rf, copilul nostru Ianis a \\u00eenceput s\\u0103 tremure u\\u0219or. L-am luat rapid \\u00een bra\\u021be \\u0219i am pornit cobor\\u00e2rea. Nu mai sim\\u021beam nimic altceva dec\\u00e2t nevoia de a-l proteja. Nu mai aveam ham, nici marsupiu. Doar corpul meu \\u0219i corpul lui. Doar mersul \\u0219i instinctul. Nu m\\u0103 puteam opri.&nbsp;\"}},{\"id\":\"P-O_Bz4yZe\",\"type\":\"paragraph\",\"data\":{\"text\":\"La un moment dat, b\\u0103rba\\u021bii din grup ne-au ajuns din urm\\u0103 si m-au ajutat. \\u00cencepusem sa simt c\\u0103-mi cedeaz\\u0103 genunchii. Dar nu voiam s\\u0103 m\\u0103 opresc. \\u00cen mine se desf\\u0103\\u0219ura o alt\\u0103 lupt\\u0103: \\u00eentre nevoia de sus\\u021binere \\u0219i vechiul program c\\u0103 \\u201etrebuie s\\u0103 pot singur\\u0103\\u201d.\"}},{\"id\":\"z_5o2X3S2L\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00centre timp, cei r\\u0103ma\\u0219i sus au intrat \\u00eentr-o medita\\u021bie profund\\u0103 ghidat\\u0103 de R\\u0103zvan. George a avut si mai multe con\\u0219tientiz\\u0103ri. Iar la cobor\\u00e2re, a mai vorbit cu R\\u0103zvan. Despre r\\u0103d\\u0103cinile sale. Despre reac\\u021biile sale. Despre cum se mo\\u0219tenesc \\u0219i se repet\\u0103 tiparele, p\\u00e2n\\u0103 le vedem cu adev\\u0103rat.\"}},{\"id\":\"FMI8NZiijZ\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":false,\"withBackground\":true,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/FE7aeRpzgqyX9dFUrZ4lm5C1C9DV9oQTQvS6OmKj.jpg\"}}},{\"id\":\"EZzxZzlJEM\",\"type\":\"header\",\"data\":{\"text\":\"Ziua 5 \\u2013 Bl\\u00e2nde\\u021bea \\u00een mijlocul ghe\\u021bii \\u0219i focului\",\"level\":2}},{\"id\":\"h7f_0UOiS9\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ziua a \\u00eenceput cu respira\\u021bia. Cu acel gest primordial care ne leag\\u0103 de via\\u021b\\u0103 \\u2013 o respira\\u021bie con\\u0219tient\\u0103, ghidat\\u0103 de Bogdan B\\u0103nculescu, \\u00eentr-o variant\\u0103 profund\\u0103 \\u0219i transformatoare a metodei Wim Hof. Am fost ghida\\u021bi de vocea lui \\u0219i de prezen\\u021ba bl\\u00e2nd\\u0103 a so\\u021biei sale, care s-a asigurat ca fiecare dintre noi este \\u00een siguran\\u021b\\u0103 \\u00een ad\\u00e2ncul propriei fiin\\u021be.\"}},{\"id\":\"-qRUyxmD2t\",\"type\":\"paragraph\",\"data\":{\"text\":\"Acolo, \\u00een lini\\u0219tea dintre dou\\u0103 respira\\u021bii, ceva s-a \\u00eent\\u00e2mplat. Pentru mine, Sandra, aceast\\u0103 c\\u0103l\\u0103torie prin oxigen \\u0219i t\\u0103cere a fost una dintre cele mai intense tr\\u0103iri de iubire pur\\u0103. Am sim\\u021bit o pace at\\u00e2t de vast\\u0103, at\\u00e2t de str\\u0103lucitoare \\u0219i totu\\u0219i at\\u00e2t de discret\\u0103, \\u00eenc\\u00e2t orice cuv\\u00e2nt pare prea mic pentru a o descrie. Nu a fost doar o stare emo\\u021bional\\u0103, ci o con\\u0219tientizare a faptului c\\u0103 iubirea nu trebuie c\\u0103utat\\u0103 \\u2013 ea este, mereu a fost, mereu va fi. A fost o \\u00eent\\u00e2lnire cu un spa\\u021biu interior unde nu mai exist\\u0103 fric\\u0103, judecat\\u0103, grab\\u0103 sau lips\\u0103. Doar iubire.\"}},{\"id\":\"pIHXqCy8fP\",\"type\":\"paragraph\",\"data\":{\"text\":\"\\u00cen acela\\u0219i timp, George era purtat de aceea\\u0219i respira\\u021bie \\u00eentr-o alt\\u0103 viziune \\u2013 una biblic\\u0103, profund simbolic\\u0103, \\u00een care imaginea lui Iisus r\\u0103stignit i-a ap\\u0103rut nu ca o scen\\u0103 a durerii, ci ca o lec\\u021bie de prezen\\u021b\\u0103. L-a v\\u0103zut respir\\u00e2nd. A sim\\u021bit c\\u0103 ceea ce l-a sus\\u021binut pe cruce nu a fost puterea fizic\\u0103 sau lupta, ci bl\\u00e2nde\\u021bea cu care a acceptat suferin\\u021ba \\u0219i compasiunea cu care i-a privit chiar \\u0219i pe cei care \\u00eel r\\u0103neau. \\u0218i \\u00een acea imagine, George a \\u00een\\u021beles c\\u0103 iubirea adev\\u0103rat\\u0103 nu are nevoie s\\u0103 fie ap\\u0103rat\\u0103. Ea se ofer\\u0103, \\u0219i tocmai \\u00een aceast\\u0103 oferire necondi\\u021bionat\\u0103, ea transform\\u0103. Cei care au b\\u0103tut cuiele au fost, paradoxal, primii care s-au trezit \\u2013 nu din fric\\u0103, ci din recunoa\\u0219terea sacralit\\u0103\\u021bii pe care o atinseser\\u0103.\"}},{\"id\":\"LMsKiiKnqB\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dup\\u0103 aceast\\u0103 deschidere, a venit r\\u00e2ndul ghe\\u021bii. Ne-am scufundat r\\u00e2nd pe r\\u00e2nd \\u00een b\\u0103ile reci, \\u00een t\\u0103cere \\u0219i prezen\\u021b\\u0103. \\u00centre limitele corpului \\u0219i libertatea min\\u021bii s-a creat un spa\\u021biu sacru, unde nimic nu mai conta \\u00een afar\\u0103 de respira\\u021bie \\u0219i inten\\u021bie. \\u0218i aici, ca \\u0219i \\u00een via\\u021b\\u0103, cu c\\u00e2t te \\u00eempotrive\\u0219ti mai mult, cu at\\u00e2t doare mai tare. Dar c\\u00e2nd alegi s\\u0103 r\\u0103m\\u00e2i prezent, bl\\u00e2nd, \\u00eemp\\u0103cat, frigul devine un aliat, nu un du\\u0219man. Am sim\\u021bit cum, \\u00een cele c\\u00e2teva minute de t\\u0103cere \\u00eenghe\\u021bat\\u0103, durerea se transform\\u0103 \\u00een rezilien\\u021b\\u0103.\"}},{\"id\":\"T2M7OIjAuA\",\"type\":\"paragraph\",\"data\":{\"text\":\"Seara, dup\\u0103 aceast\\u0103 zi de paradoxuri \\u0219i revela\\u021bii, R\\u0103zvan ne-a condus \\u00eentr-o medita\\u021bie de recunoa\\u0219tere a versiunilor noastre noi \\u2013 acele \\u201eNoi\\u201d care au ap\\u0103rut dup\\u0103 ce am s\\u0103rit \\u00een gol, am urcat muntele, am stat \\u00een \\u00eentuneric \\u0219i am intrat \\u00een ghea\\u021b\\u0103. Ne-a invitat s\\u0103 ne privim cu ochi proaspe\\u021bi, ca \\u0219i cum ne-am re\\u00eent\\u00e2lni dup\\u0103 o lung\\u0103 absen\\u021b\\u0103 \\u0219i ne-am spune: \\u201eTu e\\u0219ti? Da, tu e\\u0219ti. Dar altfel.\\u201d\"}},{\"id\":\"854o_acs_U\",\"type\":\"paragraph\",\"data\":{\"text\":\"Dup\\u0103 aceast\\u0103 \\u00eent\\u00e2lnire cu noul nostru sine, am f\\u0103cut ultimul pas: focul. Am p\\u0103\\u0219it pe c\\u0103rbunii aprin\\u0219i nu ca un test, ci ca un ritual. Fiecare pas peste jar a ars o limitare, o team\\u0103, o convingere veche. Un \\u201enu pot\\u201d sau un \\u201enu sunt destul\\u201d. Pentru mine, Sandra, a fost momentul \\u00een care am sim\\u021bit \\u00een toat\\u0103 fiin\\u021ba inten\\u021bia de a transforma vechiul \\u201enu merit\\u201d \\u00eentr-un \\u201emerit\\u201d viu, cald, hr\\u0103nitor. Am p\\u0103\\u0219it \\u00een aceast\\u0103 afirma\\u021bie ca \\u00eentr-un leg\\u0103m\\u00e2nt nou cu mine \\u00eens\\u0103mi: merit s\\u0103 primesc, merit s\\u0103 d\\u0103ruiesc, merit s\\u0103 fiu. A\\u0219a cum sunt.\"}},{\"id\":\"45BuryKb_i\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru George, focul a fost punctul final al unui proces t\\u0103cut, dar intens. A sim\\u021bit, pur \\u0219i simplu, c\\u0103 poate. C\\u0103 tot ceea ce p\\u0103rea imposibil sau rezervat altora este acum disponibil. A sim\\u021bit c\\u0103 inima lui s-a deschis \\u0219i c\\u0103 drumul lui nu mai are nevoie de permisiuni, ci doar de prezen\\u021b\\u0103.\"}},{\"id\":\"QfYwcifG7S\",\"type\":\"paragraph\",\"data\":{\"text\":\"A fost o zi \\u00een care am ars \\u0219i am \\u00eenghe\\u021bat. \\u0218i totu\\u0219i, \\u00een mijlocul acestor extreme, am descoperit o bl\\u00e2nde\\u021be care nu mai depinde de condi\\u021biile exterioare. O bl\\u00e2nde\\u021be care devine putere, atunci c\\u00e2nd alegi s\\u0103 fii cu totul acolo, \\u00een via\\u021b\\u0103, \\u00een tine, \\u00een acum.\"}},{\"id\":\"pWlhqFTczg\",\"type\":\"header\",\"data\":{\"text\":\"Ziua 6 \\u2013 Integrarea final\\u0103\",\"level\":2}},{\"id\":\"L7HQHy3IEq\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ne-am trezit \\u00een ultima diminea\\u021b\\u0103 a retreatului cu o emo\\u021bie greu de numit, dar u\\u0219or de sim\\u021bit \\u00een piept.&nbsp;Pentru prima oar\\u0103 dup\\u0103 mult timp \\u2013 sau poate pentru prima oar\\u0103 cu adev\\u0103rat \\u2013 ne-am privit cu ochi cura\\u021bi, f\\u0103r\\u0103 a\\u0219tept\\u0103ri, f\\u0103r\\u0103 proiec\\u021bii. Doar iubire \\u0219i recuno\\u0219tin\\u021b\\u0103. At\\u00e2t. At\\u00e2t de simplu, \\u0219i totu\\u0219i at\\u00e2t de vast.\"}},{\"id\":\"_xJU4UEb_k\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ne-am a\\u0219ezat \\u00een cerc pentru ultima medita\\u021bie \\u00eempreun\\u0103, iar inimile noastre parc\\u0103 \\u0219tiau deja c\\u0103 acest moment nu \\u00eenchide nimic, ci deschide. A fost o medita\\u021bie de integrare, dar \\u0219i de reamintire. A tot ceea ce suntem. A tot ceea ce am descoperit, eliberat, vindecat \\u0219i trezit. Am respirat \\u00eempreun\\u0103 nu doar aerul acelor mun\\u021bi, ci tot ceea ce devenisem \\u00een doar c\\u00e2teva zile. Am respirat adev\\u0103rul noului \\u201eeu\\u201d care s-a n\\u0103scut printre lacrimi, salturi, foc, ghea\\u021b\\u0103, r\\u00e2sete \\u0219i revela\\u021bii.\"}},{\"id\":\"meHu6BdQv5\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru noi, pentru mine \\u0219i George, acea diminea\\u021b\\u0103 a fost o rug\\u0103ciune vie. Am sim\\u021bit o recuno\\u0219tin\\u021b\\u0103 profund\\u0103 pentru fiecare moment tr\\u0103it aici. Pentru fiecare bucat\\u0103 de adev\\u0103r, fiecare oglind\\u0103 dureroas\\u0103, fiecare revela\\u021bie \\u0219i fiecare umbr\\u0103 luminat\\u0103.\"}},{\"id\":\"eXfspt6AWj\",\"type\":\"paragraph\",\"data\":{\"text\":\"Ne-am privit unul pe altul \\u0219i am \\u0219tiut: am integrat feluri noi de a fi. Ne-am recunoscut \\u00een tot ce am devenit \\u0219i ne-am onorat drumul. Am sim\\u021bit c\\u00e2t de multe putem duce acas\\u0103 din acest spa\\u021biu \\u2013 nu lucruri, nu concepte, ci energie vie, sacralitate, iubire, prezen\\u021b\\u0103. Ne-am conectat, am\\u00e2ndoi, cu divinul din noi \\u0219i cu darul pe care \\u00eel putem aduce \\u00een lume, nu din obliga\\u021bie, ci din abunden\\u021b\\u0103.\"}},{\"id\":\"__A1JxYfSI\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru George, a fost momentul \\u00een care a sim\\u021bit limpede c\\u0103 tot ceea ce a tr\\u0103it aici l-a a\\u0219ezat \\u00een \\u00eencredere. O \\u00eencredere nou\\u0103, lini\\u0219tit\\u0103, curat\\u0103. O \\u00eencredere c\\u0103 poate duce lumea pe care o viseaz\\u0103 mai aproape de realitate \\u2013 nu for\\u021b\\u00e2nd, ci tr\\u0103ind autentic.\"}},{\"id\":\"TSvK_gLMe-\",\"type\":\"paragraph\",\"data\":{\"text\":\"Pentru mine, Sandra, a fost ca \\u0219i cum inima mea s-a a\\u0219ezat pentru prima oar\\u0103 \\u00eentr-un cuib moale. Am sim\\u021bit c\\u0103 pot s\\u0103 primesc tot ceea ce via\\u021ba vrea s\\u0103-mi ofere, f\\u0103r\\u0103 s\\u0103 mai cred c\\u0103 trebuie s\\u0103 dovedesc ceva. Am sim\\u021bit c\\u0103 merit. Merit iubirea, bl\\u00e2nde\\u021bea, binecuv\\u00e2ntarea, via\\u021ba \\u00eentreag\\u0103 \\u2013 nu pentru c\\u0103 am suferit sau am luptat, ci pentru c\\u0103 sunt.\"}},{\"id\":\"nKN4P3NYCU\",\"type\":\"paragraph\",\"data\":{\"text\":\"Aceast\\u0103 diminea\\u021b\\u0103 a fost pentru noi o poart\\u0103. Nu de plecare, ci de revenire. Pentru c\\u0103 nu mai plec\\u0103m din acest spa\\u021biu \\u2013 \\u00eel lu\\u0103m cu noi. \\u00cen felul \\u00een care ne \\u021binem de m\\u00e2n\\u0103. \\u00cen felul \\u00een care ne privim copilul. \\u00cen felul \\u00een care construim \\u00eempreun\\u0103 ceea ce vis\\u0103m.\"}},{\"id\":\"_-JiHZVmL-\",\"type\":\"paragraph\",\"data\":{\"text\":\"C\\u00e2nd am cobor\\u00e2t de pe munte, nu am cobor\\u00e2t doar cu bagaje \\u0219i obiecte. Am cobor\\u00e2t cu un nou fel de a tr\\u0103i. Cu un nou fel de a iubi. Cu o nou\\u0103 pace care nu se mai teme de furtuni. \\u0218i cu promisiunea t\\u0103cut\\u0103 c\\u0103 acest \\u00eenceput nu va fi uitat.\"}},{\"id\":\"rThrVUUzYw\",\"type\":\"paragraph\",\"data\":{\"text\":\"Privind \\u00eenapoi, sim\\u021bim cum fiecare moment, fiecare respira\\u021bie, fiecare lacrim\\u0103 a fost parte dintr-un dans sacru, orchestrat cu iubire de o for\\u021b\\u0103 mai mare dec\\u00e2t noi.\"}},{\"id\":\"h-BRI-D5i5\",\"type\":\"paragraph\",\"data\":{\"text\":\"Suntem profund recunosc\\u0103tori lui R\\u0103zvan, care ne-a ghidat \\u00een toate aceste zile ca un pod \\u00eentre lumi \\u2013 cu muzica lui, cu medita\\u021biile, cu t\\u0103cerea \\u0219i cu privirea mereu prezent\\u0103.\"}},{\"id\":\"2S0RS0n_kD\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mul\\u021bumim Ramonei, care a sus\\u021binut \\u00eentregul proces cu bl\\u00e2nde\\u021bea \\u0219i for\\u021ba ei esen\\u021bial\\u0103!\"}},{\"id\":\"lnllbyV86H\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mul\\u021bumim Cristinei, care ne-a v\\u0103zut prin obiectiv \\u0219i a \\u0219tiut s\\u0103 surprind\\u0103 nu doar fe\\u021bele, ci st\\u0103rile noastre, p\\u0103str\\u00e2nd vie amintirea acestui spa\\u021biu sacru!&nbsp;\"}},{\"id\":\"AayM-WEYyK\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mul\\u021bumim celor care au fost parte din cerc \\u2013 fiecare suflet care a avut curajul s\\u0103 simt\\u0103, s\\u0103 se dezv\\u0103luie, s\\u0103 tac\\u0103 \\u0219i s\\u0103 c\\u00e2nte \\u00eempreun\\u0103 cu noi!\"}},{\"id\":\"bqx6bQ-eik\",\"type\":\"paragraph\",\"data\":{\"text\":\"Mul\\u021bumim celor care ne-au conectat, celor care ne-au g\\u0103zduit, celor care ne-au hr\\u0103nit \\u2013 echipa de la cazare, oamenii din buc\\u0103t\\u0103rie, para\\u0219uti\\u0219tii cu care am zburat, \\u00eengerii vizibili \\u0219i invizibili care au f\\u0103cut acest retreat posibil!\"}},{\"id\":\"SNXYz8Qu7e\",\"type\":\"paragraph\",\"data\":{\"text\":\"R\\u0103m\\u00e2nem cu inima plin\\u0103 de recuno\\u0219tin\\u021b\\u0103. \\u0218i cu o singur\\u0103 certitudine: acolo unde iubirea ghideaz\\u0103 pa\\u0219ii, via\\u021ba devine un miracol tr\\u0103it \\u00eempreun\\u0103!\"}},{\"id\":\"Nn2ABRrIhM\",\"type\":\"image\",\"data\":{\"caption\":\"\",\"withBorder\":true,\"withBackground\":true,\"stretched\":false,\"file\":{\"url\":\"http:\\/\\/lotusretreat.ro\\/storage\\/editorjs\\/final\\/osMTuiPVYHDLqlwH7Sn5LPautm4Mkc6jUlXLngyb.jpg\"}}}],\"version\":\"2.31.0-rc.7\"}', 7, 'Asociatia Lotus Retreat', '2025-07-02 11:25:05', '2025-07-03 14:49:08');
INSERT INTO `post_categories` (`id`, `name`, `slug`, `picture`, `description`, `created_at`, `updated_at`) VALUES
(1, 'Despre noi', 'despre_noi', NULL, '<p>Cine suntem cu adevarat&nbsp;</p><p>Povestile, viziunile si pasii ce ne-au adus aici. Afla ce ne inspira si ce ne uneste</p>', '2025-05-08 17:38:20', '2025-05-13 09:36:34'),
(2, 'Dispozitive orgonice', 'dispozitive_orgonice', NULL, '<p>Descopera cum lucreaza, ce contin si de ce fiecare orgon este un canal de echilibru si transformare</p>', '2025-05-08 17:38:20', '2025-05-13 09:38:11'),
(4, 'Părinți/Copii', 'părinți', NULL, '<p>Articole cu si despre parinti&nbsp;</p>', '2025-06-04 07:42:45', '2025-06-04 07:42:45'),
(5, 'Despre vindecare', 'despre_vindecare', NULL, '<p>Aici găsești articole care te susțin în procesul de conștientizare, eliberare și reconectare cu tine. Scriem cu blândețe despre răni emoționale, mecanisme de protecție, iertare, deschidere și puterea de a primi binele în viața ta.</p><p>💛 Pentru că vindecarea nu înseamnă să repari ce e stricat, ci să-ți amintești cine ești cu adevărat.</p>', '2025-06-13 19:28:34', '2025-06-13 19:55:35');
