INSERT INTO `services` (`id`, `name`, `description`, `picture`, `disabled`, `price`, `created_at`, `updated_at`) VALUES
(1, 'Întoarcerea Acasă – Terapie cu Două Inimi', '<p>Această terapie este o călătorie interioară ghidată de Sandra &amp; George într-un spațiu sigur, conținut și profund susținut energetic. Fiecare sesiune este un proces personalizat de transformare, în care lucrăm cu întreaga ființă: minte, corp, emoții, subconștient și câmpurile energetice.</p><p>Metoda noastră combină mai multe direcții terapeutice, atât științifice cât și energetice, rezultând un proces complex și profund, adaptat nevoilor fiecărui suflet care ajunge la noi:</p><p>🔹 Terapie energetică și „chirurgie astrală”:<br>George lucrează intuitiv și direct în câmpul tău energetic, printr-o formă subtilă de intervenție numită chirurgie astrală. Aceasta presupune curățarea, reașezarea și armonizarea energiilor blocate sau distorsionate, eliberarea tiparelor vechi și susținerea fluxului vital în corp.&nbsp;</p><p>🔹 Meditații ghidate &amp; exerciții de respirație (tehnici de hipnoza):<br>Fiecare sesiune include un moment de centrare profundă și conectare cu corpul, sufletul și respirația. Te vom ghida într-o meditație personalizată care poate varia de la regresie până la reconectarea cu părți pierdute din tine. Lucrăm în stări modificate de conștiință, într-un spațiu de relaxare profundă, unde subconștientul poate fi accesat cu ușurință și pot fi transformate tipare de suferință, loialități invizibile sau traume transgeneraționale.</p><p>🔹 NLP (Programare Neuro-Lingvistică):<br>Lucrăm conștient cu limbajul interior și convingerile care te blochează. NLP-ul este un instrument valoros pentru transformarea modului în care te raportezi la tine și la viață, ajutându-te să accesezi resurse noi și perspective vindecătoare.</p><p>🔹 Terapie narativă:<br>Te ghidăm să îți re-scrii povestea interioară, să te eliberezi de vechile narațiuni care ți-au definit identitatea și să alegi, conștient, ce vrei să porți mai departe în sufletul tău.</p><p>🔹 Fundament psihologic:<br>Avem și o bază solidă în psihologie – Sandra a finalizat studiile în acest domeniu – astfel că tot ceea ce facem este integrat într-un cadru ancorat, empatic și profesional.</p><p>&nbsp;</p><p><strong>Cât durează și cât costă?</strong></p><p>&nbsp;Sesiunile durează între 1 oră și jumătate și 2 ore, în funcție de nevoile tale din acel moment. Sesiunile pot avea loc online sau fizic, în funcție de disponibilitatea ta și de cum rezonezi cu prezența în spațiu.<br>&nbsp;Schimbul energetic pentru o sesiune online este de 444 lei, iar sesiunea fizica 555 lei.</p><p>&nbsp;</p><p>&nbsp;</p><p><strong>Pentru cine este această terapie?</strong></p><p>Este potrivită pentru tine dacă:<br>&nbsp;&nbsp;&nbsp;&nbsp;•&nbsp;&nbsp;&nbsp;&nbsp;simți că ai lucrat deja cu tine, dar ceva încă te blochează sau te trage înapoi,<br>&nbsp;&nbsp;&nbsp;&nbsp;•&nbsp;&nbsp;&nbsp;&nbsp;te confrunți cu anxietate, frici, gol interior, lipsă de sens sau dezechilibru emoțional,<br>&nbsp;&nbsp;&nbsp;&nbsp;•&nbsp;&nbsp;&nbsp;&nbsp;ai trecut prin evenimente dureroase sau traume și dorești susținere pentru a le alchimiza,<br>&nbsp;&nbsp;&nbsp;&nbsp;•&nbsp;&nbsp;&nbsp;&nbsp;îți dorești o vindecare blândă, profundă și completă – nu doar pe un plan, ci pe toate.</p><p>⸻</p><p>Dacă simți chemarea să te întorci către tine și să te lași susținut/ă, scrie-ne și vom programa cu drag o întâlnire.<br>Spațiul nostru este sacru. Deschis, dar cu limite sănătoase. Blând, dar profund transformator.</p>', 'services/FtyLHqPatasg2vOtFcDVmyGPIoZpGbrVmS3zIUen.jpg', 0, 444.00, '2025-06-16 15:38:21', '2025-07-03 09:55:26');
INSERT INTO `settings` (`id`, `hero_text_1`, `hero_text_2`, `hero_text_3`, `shop_text_1`, `shop_text_2`, `shop_text_3`, `event_text_1`, `iban`, `data`, `phone_number`, `email`, `shop_img_1`, `shop_img_2`, `shop_img_3`, `shop_img_4`, `event_img`, `mission_text`, `mission_bullets`, `about_text`, `selected_blog_posts`, `selected_products`, `footer_text`, `footer_follow_us`, `created_at`, `updated_at`) VALUES
(1, 'Bine ai venit Acasă!', 'Un loc unde Dumnezeu, creația si iubirea ne ajuta sa ne reamintim cine suntem cu adevărat.', 'Aici găsești spațiu pentru eliberare, inspirație si reconectare.', '<p>Lasă-te ghidat de intuitie…</p>', '<p>Catre instrumentul potrivit sufletului tau</p>', 'Alege ce îți potențează vibrația!', '<p>Experiente unice prin terapii si evenimente speciale</p>', 'RO61BTRLRONCRT0CS4431102', 'ASOCIATIA LOTUS RETREAT', '0753645442', 'asociatialotusretreat@gmail.com', 'settings/WnK8UsfJsUcEpbiaT6aOY2n6JbXN1Gu0uh6Xs8D1.jpg', 'settings/RiJUIbCSylK4cBl315yN0aOeVo09zgItpxF6zUBT.jpg', 'settings/FGsA80Jy8lCoEEyXcWgMuO5cqZw9SCnSp0uTnm2Z.jpg', 'settings/MzWyH5DFbMx1QIFyEt7oOlax0OQwxAdcOLSwId8l.jpg', 'settings/VRFnbTO9tANqh8UNUVOMQwI0JIj9WU5ptxpEe0Uu.jpg', 'Eliberăm, creștem si ne susținem reciproc', '[\"Oferim un spa\\u021biu pentru introspec\\u021bie \\u0219i eliberare prin medita\\u021bie \\u0219i explorare interioar\\u0103.\",\"Lucr\\u0103m cu frecven\\u021be, respira\\u021bie, scanare corporal\\u0103 \\u0219i activarea memoriei sufletului.\",\"Conect\\u0103m terapeu\\u021bi din domenii variate pentru a cultiva vindecarea \\u0219i evolu\\u021bia.\",\"Punem bazele unui loc fizic dedicat retreaturilor, medita\\u021biilor \\u0219i terapiilor.\",\"Integr\\u0103m spiritualitatea \\u00een via\\u021ba cotidian\\u0103, dincolo de concepte sau teorii.\",\"Folosim sunetul, simboluri \\u0219i activ\\u0103ri pentru expansiunea con\\u0219tiin\\u021bei \\u0219i echilibru l\\u0103untric.\",\"Cre\\u0103m obiecte ca purt\\u0103tori de energie pur\\u0103, menite sa sus\\u021bin\\u0103 armonia si echilibrul interior.\",\"Misiunea noastr\\u0103 este s\\u0103 sus\\u021binem transformarea autentic\\u0103, oferind nu doar tehnici, ci \\u0219i un spa\\u021biu sigur.\"]', '<p>Dincolo de tot ceea ce oferim, suntem doi oameni uniți de aceleași valori, aceeași misiune și de același dor: acela de a crea un spațiu în care sufletul să se simtă acasă.</p><p><br>Am scris un articol pe blog despre noi prin care îți deschidem poarta spre povestea noastră – cum a început totul, ce ne-a transformat și cum s-a născut visul unui centru viu, dedicat vindecării, reconectării și adevărului interior.</p><p><br>Te invităm să ne cunoști mai profund și, dacă simți chemarea, să faci parte din această viziune care se construiește din iubire, intenție și credință.</p>', '[\"12\",\"11\",\"10\"]', '[\"53\",\"31\",\"9\",\"8\"]', '<p>© 2025 Lotus. All rights reserved.</p>', 'https://www.facebook.com/share/15vEdoHcbM/?mibextid=wwXIfr', '2025-05-08 17:38:20', '2025-07-11 10:52:37');
